export const GUIDES: Guide[] = [
  { id: "asylum-waiting", cat: "Asylum Process", icon: "⏳", content: { en: { title: "Waiting for Your Asylum Decision", summary: "What to expect while your asylum claim is being processed — your cards, rights, payments, and what happens next.", steps: ["Your ARC card (Application Registration Card) is your primary ID while your asylum claim is active. It proves you have an ongoing claim. Use it to: register with a GP or NHS service, access asylum support accommodation, open certain bank accounts (Monese accepts an ARC card), and enrol in ESOL or college.", "Your ARC card CANNOT be used as a right-to-work document unless it specifically says 'Permitted to Work' on the front. It is NOT a travel document — you cannot leave the UK and re-enter on it. It is NOT equivalent to a BRP or eVisa.", "Your ASPEN card is your asylum support payment card. As of 2025/26 the standard rate is £49.18/week for a single adult (higher if you have children). Payments arrive weekly. The card works like a Visa debit card at any shop that accepts Visa. Note: older ASPEN cards cannot withdraw cash from ATMs.", "Current Home Office processing times: 6–18+ months for most claims, and longer for complex cases or certain nationalities. You can check your case status by contacting the Asylum Helpline on 0808 8000 631 (free, Mon–Fri 9am–5pm) or by asking your solicitor to make enquiries.", "If you need to chase the Home Office: ask your solicitor to write to the case-owner or the National Asylum Intake Unit. If you do not have a solicitor, call the Asylum Helpline (0808 8000 631) or contact a local law centre.", "If your decision is POSITIVE (refugee status granted): you will receive a refugee recognition letter. You then have 42 days to leave asylum accommodation and set yourself up — see the Move-On guide for everything you must do immediately. Check the exact end date on your asylum support discontinuation letter.", "If your decision is NEGATIVE: you will usually have the right to appeal. You have 14 or 28 days to lodge an appeal (the letter will say which). Always consult a solicitor immediately — do not miss the deadline. If you have new evidence not previously considered, you may be able to submit a 'fresh claim'.", "Your rights while waiting: you have the right to free NHS care, your children have the right to attend school, you have the right to asylum accommodation and Section 95 support if destitute. If you are refused but cannot safely return to your home country, you may qualify for Section 4 support. You also have the right to free legal aid for your asylum case.", "Reporting requirements: you may be required to report regularly to an immigration reporting centre. The letter you received will tell you your reporting schedule. Missing a reporting appointment without a good reason can lead to the Home Office treating you as having absconded, which can seriously harm your case.", "⚠ Never pay anyone to check your case status — it is free. Never give your ARC card or ASPEN card to anyone else."] } }, cost: "Free", time: "Ongoing — 6–18+ months", bring: ["ARC card", "Any letters from the Home Office"], links: [{ name: "Asylum Helpline (0808 8000 631)", url: "https://www.gov.uk/asylum-support" }, { name: "Check your asylum case (GOV.UK)", url: "https://www.gov.uk/asylum-support/further-information" }, { name: "Legal aid for asylum (GOV.UK)", url: "https://www.gov.uk/legal-aid" }, { name: "Refugee Council asylum support", url: "https://www.refugeecouncil.org.uk/help-for-refugees/asylum-support/" }, { name: "Section 4 support (GOV.UK)", url: "https://www.gov.uk/asylum-support/section-4-support" }] },
  { id: "evisa", cat: "Digital Status", icon: "📱", content: { en: { title: "Your eVisa & UKVI Account", summary: "BRPs expired Dec 2024. Your immigration status is now 100% digital — set up your UKVI account now.", steps: ["All BRPs (Biometric Residence Permits) expired 31 December 2024. Your immigration status has NOT changed — only the way you prove it has changed.", "⚠️ JUNE 2026 DEADLINE: The 18-month grace period for using expired BRPs to generate share codes ends in June 2026. After that date, you MUST use your UKVI account directly. If you haven't set one up yet, do it today — visit gov.uk/evisa.", "Since June 2025, expired BRPs are NOT accepted by airlines or border staff for travel. You must show your passport linked to your UKVI eVisa instead.", "Check your email for noreply@notifications.service.gov.uk — your UKVI account may already exist. Search your inbox and spam folder.", "No UKVI account yet? Visit gov.uk/evisa — it is free and takes about 10 minutes. You will need your email address and your BRP number or passport details.", "Link your passport to your UKVI account BEFORE your next trip. Airlines check eVisa status digitally — an unlinked passport will be rejected at check-in.", "From 25 February 2026, all new visa applicants receive eVisas only. No physical documents are issued for any new visa applications.", "Screenshot your eVisa status page (the page showing your name and conditions) and save it offline in your Photos app — essential if you have no internet signal.", "⚠ If you have changed your name, got a new passport, or moved address, update your UKVI account at gov.uk/evisa immediately — outdated details cause problems at borders and with employers."] } }, cost: "Free", time: "10 min", bring: ["Email address", "BRP number or passport details"], links: [{ name: "Set up eVisa (GOV.UK)", url: "https://www.gov.uk/evisa" }, { name: "Update UKVI account details", url: "https://www.gov.uk/evisa/update-your-ukvi-account-details" }, { name: "eVisa help and guidance (GOV.UK)", url: "https://www.gov.uk/government/publications/updates-on-the-move-to-evisas/updates-on-the-move-to-evisas" }, { name: "Travel with an eVisa (GOV.UK)", url: "https://www.gov.uk/evisa/travel-with-evisa" }] },
  { id: "sharecode", cat: "Digital Status", icon: "🔗", content: { en: { title: "Share Codes", summary: "Prove your right to work, rent, or access services.", steps: ["Log in to UKVI → 'Prove your status'. Choose: Right to Work, Right to Rent, or General.", "Right to Work codes start with 'W'. Right to Rent codes start with 'R'. Don't mix them up.", "Codes valid 90 days. Generate a new one each time you need it.", "Give the code + your date of birth to your employer or landlord. They verify online.", "EU Settled Status: share code is your ONLY proof. No physical card exists.", "⚠ Never pay anyone for a share code. The GOV.UK service is always free."] } }, cost: "Free", time: "2 min", bring: ["UKVI account login"], links: [{ name: "Prove right to work (GOV.UK)", url: "https://www.gov.uk/prove-right-to-work" }, { name: "Prove right to rent (GOV.UK)", url: "https://www.gov.uk/prove-right-to-rent" }, { name: "Check someone's status (GOV.UK)", url: "https://www.gov.uk/view-right-to-work" }] },
  { id: "life-admin", cat: "Documents & ID", icon: "📑", content: { en: { title: "Life Admin & Strict Rules", summary: "British bureaucracy is strict. Ignoring these rules can result in massive fines or court action.", steps: ["**The TV Licence (£174.50/year):** You must pay this if you watch ANY live TV or use BBC iPlayer — even on a phone. The fine for non-payment is £1,000. If you never watch live TV, you must legally declare you don't need one at tv-licensing.co.uk.", "**Council Tax:** A local tax paid to your council. It funds local services. The amount depends on your property band. Students are exempt. If you live alone, apply for a 25% single-person discount. [URGENT] Ignore this bill and you will face court action.", "**The MOT:** Cars older than 3 years need an annual safety test (~£55). Fail it and you cannot legally drive on public roads. The fine for driving without an MOT is £1,000.", "**P60 and P45 Forms:** Your P60 is your annual tax summary. Keep every single one — you will need them for ILR and citizenship applications. A P45 is issued when you leave a job; give it to your next employer.", "**Subject Access Request (SAR):** If you lose your Home Office documents, you can request your entire immigration history for free. Search 'Home Office SAR' on GOV.UK. It takes 1 month."] } }, cost: "Varies", time: "Read immediately", bring: [], links: [{ name: "TV Licensing", url: "https://www.tvlicensing.co.uk" }, { name: "Council Tax Info", url: "https://www.gov.uk/council-tax" }, { name: "Request Home Office records", url: "https://www.gov.uk/government/publications/requests-for-personal-data-uk-visas-and-immigration/request-personal-information-held-by-uk-visas-and-immigration" }] },
  { id: "nrpf", cat: "Asylum Process", icon: "⚠️", content: { en: { title: "No Recourse to Public Funds (NRPF)", summary: "NRPF restricts most benefits. Know what you CAN still access.", steps: ["NRPF means you cannot claim: Universal Credit, Housing Benefit, Child Tax Credit.", "You CAN still access: full NHS care, state schools, Statutory Sick Pay, child protection.", "Destitute with children? Your council MUST help under Section 17, Children Act 1989.", "Changed circumstances (illness, domestic abuse)? Apply to have NRPF removed.", "NRPF Network provides free specialist advice."] } }, cost: "Free", time: "Read now", bring: [], links: [{ name: "NRPF Network", url: "https://www.nrpfnetwork.org.uk" }, { name: "Find immigration adviser (GOV.UK)", url: "https://www.gov.uk/find-an-immigration-adviser" }] },
  { id: "bank", cat: "Money", icon: "🏦", content: { en: { title: "Opening a Bank Account", summary: "Asylum seekers: Monese accepts your ARC card directly — no share code needed. Others can use Revolut, Monzo, or Starling with a share code.", steps: ["Asylum seekers without a share code: Monese accepts your ARC card directly. No fixed address required. Apply in the Monese app.", "Revolut, Monzo, and Starling all accept share code + selfie/face scan. Approved in hours — often same day. Note: these banks generally require a share code or passport — asylum seekers who surrendered their passport to the Home Office may not have these.", "If digital banks decline: go to Barclays, NatWest, Lloyds, or HSBC in person and ask specifically for a 'basic bank account'.", "You do NOT need a fixed address. A hostel address, friend's address, or charity office address is fine.", "Credit unions accept members without UK credit history — useful for borrowing small amounts later.", "⚠ Never pay anyone to open a bank account. It is always free. Any fee request is a scam."] } }, cost: "Free", time: "Same day", bring: ["ARC card (asylum seekers)", "Share code or passport", "Smartphone"], links: [{ name: "Monese", url: "https://monese.com" }, { name: "Revolut", url: "https://www.revolut.com" }, { name: "Monzo", url: "https://monzo.com" }, { name: "Starling", url: "https://www.starlingbank.com" }, { name: "Basic bank account (GOV.UK)", url: "https://www.gov.uk/government/collections/basic-bank-accounts" }] },
  { id: "credit-score", cat: "Money", icon: "📈", content: { en: { title: "Building a UK Credit Score", summary: "You start with zero credit history in the UK. Without a score, you get rejected for phone contracts, some rentals, and almost all loans.", steps: ["When you arrive in the UK, your credit score is zero — regardless of your background, education, or income in your home country. UK lenders can only see your UK financial history. This is called a 'thin file' and it closes many doors.", "**What a zero credit score blocks:** Standard 12/24-month phone contracts (the cheapest option), mainstream personal loans, credit cards, mortgages, and some private landlord rental applications.", "**Step 1 — Open a UK bank account and use it regularly:** Monzo, Revolut, or Monese all accept refugees. Ensure your name and address on the account exactly matches all other records. Regular use builds your history.", "**Step 2 — Do NOT apply for a standard phone contract yet:** You will likely be rejected. Each rejection adds a 'hard search' to your credit file and lowers your score further. Instead, get a 30-day rolling SIM with no credit check: Giffgaff (£10/month, 40GB+), Lebara, Smarty, or Voxi. Upgrade to a contract after 12+ months of good history.", "**Step 3 — Register to vote:** This is the single fastest way to boost your score. Commonwealth citizens and those with Leave to Remain can register. Do it at gov.uk/register-to-vote.", "**Step 4 — Pay every bill on time via Direct Debit:** Council tax, energy, water — if your name is on any bill, pay it on the due date. One missed payment can damage your score for 6 years.", "**The 3-Year Rule for Mainstream UK Loans:** Most high-street banks (Lloyds, Barclays, HSBC, NatWest) require you to have had a UK address for at least **3 years** before approving a personal loan or mortgage application. This is a hard policy that even a perfect credit score cannot override in the early years. **Workarounds:** RefuAid offers interest-free loans with no UK credit history needed (refuaid.org). Local credit unions are much more flexible. After 3 years of UK address history, your options expand significantly.", "**Check your score for free (soft search — does NOT lower it):** ClearScore (powered by Equifax), Experian free tier, or Credit Karma. Check monthly.", "**Credit builder cards after 12 months:** Aqua, Vanquis, or Capital One offer cards for thin files. Use ONLY for small purchases you pay off IN FULL every month. Never carry a balance — interest rates are 39%+.", "⚠ Never use payday lenders. Never borrow from unlicensed 'loan sharks'. Both destroy your credit score and can put you in dangerous debt."] } }, cost: "Free to check", time: "6–12 months to build a usable score", bring: [], links: [{ name: "ClearScore (free credit check)", url: "https://www.clearscore.com" }, { name: "Experian (free tier)", url: "https://www.experian.co.uk" }, { name: "Register to vote (GOV.UK)", url: "https://www.gov.uk/register-to-vote" }, { name: "RefuAid (no credit history needed)", url: "https://www.refuaid.org" }] },
  { id: "uc", cat: "Money", icon: "💷", content: { en: { title: "Universal Credit", summary: "Main working-age benefit. Request an Advance on day one.", steps: ["Apply online or call 0800 328 5644 (free).", "Request UC Advance on day one — interest-free loan for the 5-week wait.", "Report full housing costs so Housing Element is included.", "Claim Child Benefit separately — after 7 Apr 2025, backdated to refugee grant date (max 3 months).", "Update your UC journal every assessment period — missed updates pause payments.", "NRPF on your eVisa? You cannot claim UC. See the NRPF guide."] } }, cost: "Free", time: "5 weeks — Advance covers wait", bring: ["Share code", "Bank details", "Rent info"], links: [{ name: "Apply for UC (GOV.UK)", url: "https://www.gov.uk/universal-credit/how-to-claim" }, { name: "Child Benefit (GOV.UK)", url: "https://www.gov.uk/child-benefit" }] },
  { id: "ni", cat: "Documents & ID", icon: "🔢", content: { en: { title: "National Insurance Number", summary: "Needed for work and tax. Start working before it arrives.", steps: ["Apply online — free, takes 20 minutes.", "You CAN work and claim benefits while waiting — tell employer it's pending.", "Format: AB 12 34 56 C. Yours for life.", "Never share your NI number on social media."] } }, cost: "Free", time: "4–16 weeks", bring: ["Passport"], links: [{ name: "Apply for NI number (GOV.UK)", url: "https://www.gov.uk/apply-national-insurance-number" }] },
  { id: "tax", cat: "Money", icon: "📋", content: { en: { title: "Tax & Payslips", summary: "How UK tax works. What to save for visa applications.", steps: ["Tax is deducted automatically via PAYE. Check your payslip monthly.", "Personal Allowance: £12,570/year tax-free. Basic rate 20% up to £50,270.", "Save every P60 and P45 — critical for future visa applications.", "Self-employed? Register with HMRC within 3 months of starting.", "⚠ Not all visas allow self-employment — check your eVisa conditions first."] } }, cost: "Free", time: "Ongoing", bring: ["NI number"], links: [{ name: "Income tax guide (GOV.UK)", url: "https://www.gov.uk/income-tax" }, { name: "Register as self-employed (GOV.UK)", url: "https://www.gov.uk/set-up-self-employed" }] },
  { id: "gp", cat: "Healthcare", icon: "🏥", content: { en: { title: "NHS & GP Registration", summary: "Free NHS care for everyone — regardless of immigration status or address.", steps: ["Find your nearest GP on the NHS website.", "GPs legally CANNOT refuse you — no address, no ID, any immigration status.", "Asylum seekers receive full free NHS care including hospital treatment, mental health, maternity, and prescriptions. You do NOT need to pay the Immigration Health Surcharge.", "Show your ARC card at the GP surgery — it confirms your right to register.", "HC2 certificate: asylum seekers on asylum support automatically qualify for free prescriptions, dental, and optical care — apply via form HC1.", "Download the NHS App (free) — book appointments, repeat prescriptions, NHS number, health records.", "NHS 111 for urgent medical advice (free, 24/7). 999 for emergencies.", "Free dental if you're on UC — tell the dentist before any treatment. **However**, finding an NHS dentist accepting new patients is currently very difficult across the UK. Use the NHS 'Find a Dentist' tool but expect to call many clinics. Many areas have long waiting lists. Dental schools (university dental hospitals) often accept new NHS patients with shorter waits."] } }, cost: "Free", time: "Same day", bring: ["Passport (helpful, not required)", "ARC card (if you have one)"], links: [{ name: "Find a GP (NHS)", url: "https://www.nhs.uk/service-search/find-a-gp" }, { name: "NHS App", url: "https://www.nhs.uk/nhs-app/" }, { name: "Find a dentist (NHS)", url: "https://www.nhs.uk/service-search/find-a-dentist" }] },
  { id: "mental", cat: "Healthcare", icon: "🧠", content: { en: { title: "Mental Health Support", summary: "Free mental health care. Seeking help is strength.", steps: ["Self-refer to NHS Talking Therapies — free CBT, no GP referral needed.", "Freedom from Torture: free therapy for survivors — 020 7697 7777.", "Crisis: Samaritans 116 123 (free 24/7) or text SHOUT to 85258.", "Domestic Abuse: 0808 2000 247 (free, 24/7, all languages)."] } }, cost: "Free", time: "Self-refer or via GP", bring: [], links: [{ name: "NHS Talking Therapies", url: "https://www.nhs.uk/mental-health/talking-therapies-medicine-treatments/talking-therapies-and-counselling/nhs-talking-therapies/" }, { name: "Freedom from Torture", url: "https://www.freedomfromtorture.org" }] },
  { id: "renting", cat: "Housing", icon: "🔑", content: { en: { title: "Renting a Home", summary: "Your rights as a renter. Landlords must accept share codes.", steps: ["Give landlords a Right to Rent share code + your date of birth. They verify online.", "Landlords CANNOT discriminate by nationality — it's unlawful.", "Search: SpareRoom, Rightmove, Zoopla. Filter by distance and budget.", "Maximum deposit is 5 weeks' rent. Must be in a government protection scheme.", "Always get a written tenancy agreement before paying anything.", "If you have no UK credit history or guarantor, some estate agents will ask for **6 months' rent in advance** instead of a deposit. If you cannot afford this, search directly for private landlords on **SpareRoom** — many are more flexible than agencies and accept UC/DSS tenants.", "⚠ Landlords cannot evict without a court order. Changing locks illegally is a criminal offence."] } }, cost: "Deposit + 1st month", time: "Start searching now", bring: ["Right-to-rent share code"], links: [{ name: "SpareRoom", url: "https://www.spareroom.co.uk" }, { name: "Rightmove", url: "https://www.rightmove.co.uk" }, { name: "Deposit protection (GOV.UK)", url: "https://www.gov.uk/tenancy-deposit-protection" }] },
  { id: "housing-help", cat: "Housing", icon: "🏠", content: { en: { title: "Council Housing & Homelessness Help", summary: "If homeless or at risk, your local council has a legal duty to help. Refugees have powerful legal protections.", steps: ["Contact your local council housing department immediately. You are a priority need as a newly recognised refugee.", "You have a PERMANENT local connection to the council area where your refugee decision was made — this right can NEVER be lost and is critical for your housing application. Moving away from your dispersal area may affect this.", "Apply for the social housing waiting list as early as possible — long waits in most cities, but being on the list is essential.", "Claim UC Housing Element immediately — this helps cover rent in private accommodation while you wait.", "Refugees at Home: free matching service connecting refugees with UK hosts who have a spare room. Especially useful during the move-on period (refugeesathome.org).", "NACCOM: national network of refugee accommodation charities — lists 90+ organisations across the UK (naccom.org.uk).", "Shelter helpline: 0808 800 4444 (free, Mon–Fri 8am–8pm) — specialist housing advice.", "Crisis charity: homelessness services across England, Scotland, and Wales (crisis.org.uk).", "⚠ Your council MUST give you emergency accommodation if you are homeless — do not accept 'we can't help' as an answer."] } }, cost: "Free", time: "Apply immediately", bring: ["Refugee decision letter", "Share code"], links: [{ name: "Find your council (GOV.UK)", url: "https://www.gov.uk/find-local-council" }, { name: "Shelter", url: "https://www.shelter.org.uk" }, { name: "Refugees at Home", url: "https://www.refugeesathome.org" }, { name: "NACCOM", url: "https://naccom.org.uk" }, { name: "Crisis", url: "https://www.crisis.org.uk" }] },
  { id: "social-housing", cat: "Housing", icon: "🏘", content: { en: { title: "Council Housing — The Real Process", summary: "There are no 'council flats' handed out automatically. Here is how social housing actually works in the UK — waiting lists, bidding, and what UC pays for rent.", steps: ["**The Misconception:** There is no such thing as simply 'applying for a council flat'. The UK social housing system has millions of people on waiting lists. In London, the average wait is 10–15+ years. In cities like Manchester or Leeds: 3–7 years. In smaller Northern towns or Glasgow: 1–3 years. You may never receive a council home in high-demand areas.", "**Step 1 — Apply as Homeless (Housing Act 1996):** If you are homeless or facing homelessness (including at the end of your 42-day move-on period), go immediately to your local council's Housing Options or Homelessness team. Do NOT wait until you are on the street. Recognised refugees are automatically 'priority need' — the council has a LEGAL DUTY to provide you with temporary accommodation.", "**What 'Temporary Accommodation' Actually Means:** This is typically a hostel, B&B, or short-term council flat arranged by the council. It is NOT your long-term home. It is often in a different part of the city or even a different town. UC Housing Element covers the cost. The goal: get out into stable private renting as soon as possible.", "**Step 2 — Join the Housing Register the Same Day:** At the council housing office, ask to apply to the Housing Register (also called Housing Waiting List or Bidding List). You will be assessed and placed in a Band — Band A (most urgent), Band B (high need, which includes newly-recognised refugees), Band C, Band D. Request this in writing.", "**Step 3 — Choice-Based Lettings (CBL) — How Properties Are Actually Allocated:** When a council or housing association property becomes available, the council advertises it on a CBL portal (examples: Homefinder, LocalOffer, Homebid — name differs by council). You log in and 'bid' (express interest) in properties you are eligible for. The eligible bidder with the most points/highest Band who bids gets offered the property. You MUST bid actively and regularly.", "**Meanwhile — Private Renting Supported by UC:** Because social housing waiting times are so long, most refugees end up renting privately long-term with Universal Credit paying most of the rent. Your UC will include a Housing Element based on the Local Housing Allowance (LHA) for your area. Look up your area's LHA rate at gov.uk/government/publications/lha-rates.", "**Local Housing Allowance (LHA) — The Rental Cap:** LHA is the maximum rent UC will cover. Single adults under 35 are entitled to the 'Shared Accommodation Rate' (SAR) — usually only enough for a room in a shared house. Adults 35+ get a 1-bedroom rate. Families get rates based on number of children. LHA rarely covers full market rent in expensive areas — expect a shortfall.", "**Long-Term — Right to Buy:** Once you have lived in social housing for at least 3 years, you may have the Right to Buy your council home at a discount (currently up to £87,200 off, £116,200 in London). This is a very long-term goal.", "⚠ Never pay anyone to 'move you up' the waiting list — it is not possible. Never give up your dispersal area local connection before securing alternative housing. Keep bidding consistently on the CBL portal — missed bids mean missed opportunities."] } }, cost: "Free", time: "Temporary housing: immediate | Social housing: 2–15+ years", bring: ["Refugee decision letter", "Share code", "Any address for mail — even a friend's"], links: [{ name: "Find your council (GOV.UK)", url: "https://www.gov.uk/find-local-council" }, { name: "Council housing overview (GOV.UK)", url: "https://www.gov.uk/council-housing" }, { name: "LHA rates (GOV.UK)", url: "https://www.gov.uk/government/publications/local-housing-allowance-lha-rates-applicable-from-april-2024-to-march-2025" }, { name: "Shelter — council housing guide", url: "https://www.shelter.org.uk/housing_advice/council_and_social_housing" }] },
  { id: "where-to-live", cat: "Housing", icon: "🗺️", content: { en: { title: "Where to Live in the UK", summary: "One of the most important decisions you'll face. This guide compares UK cities on cost, jobs, housing waits, and community — so you don't make a £10,000 mistake.", steps: ["**The Move-On Deadline:** When your refugee decision arrives, you have 42 days from your asylum support discontinuation letter to leave asylum accommodation. Your dispersal area gives you a 'local connection' right — but you are not obliged to stay there. However, moving to a new city early means joining a new housing waiting list from zero.", "**London: Highest Opportunity, Highest Risk:** The UK's largest job market and large East African communities (Peckham, Brixton, Tottenham, East London). BUT: average rent for a room in a shared house is £900–£1,400/month. LHA rates often do not cover market rents, leaving you with a monthly shortfall. Social housing waiting list: 10–15+ years. Moving to London without a confirmed job is very high risk. Better strategy: work in London, live just outside (Croydon, Stratford, Enfield, Slough).", "**Birmingham: The Balanced Choice:** UK's second-largest city. Average 1-bed rent: £700–£950/month. Social housing wait: 5–8 years in the city, 2–4 years in surrounding towns (Wolverhampton, Dudley, Sandwell). Significant East African community (Handsworth, Smethwick, Erdington). Strong engineering, healthcare, and finance job market. Fast trains to London (1hr 20min), Manchester, and Leeds.", "**Manchester & Salford: Best for Skilled Professionals:** Average 1-bed rent: £800–£1,100/month in city, £550–£800 in Salford or Stockport. Strong tech, media, and commercial sectors. Large refugee support network (Refugee Action office). Social housing waits: 3–7 years in Manchester, shorter in satellite towns. Good airport and transport links. Growing East African community.", "**Leeds & Sheffield: Engineers' Choice:** Leeds 1-bed rent: £700–£900/month. Sheffield: £550–£800/month. Both cities have large engineering, construction, and manufacturing sectors — directly relevant for civil engineers. Sheffield's Attercliffe and Rotherham have engineering firms. Leeds has financial services and a major law sector. Shorter social housing waits than London or Manchester. Very affordable cost of living.", "**Glasgow: Scotland's Hidden Advantage:** Scotland has devolved benefits and refugee policies — sometimes more generous than England. Glasgow 1-bed rent: £700–£900/month. Social housing wait: significantly shorter than English cities, 1–3 years in many areas. Glasgow City Council has processed many refugees and has strong support infrastructure. Cold winters but a strong community feeling. Note: Scottish law and some benefits differ from England.", "**Norwich, Ipswich, Cambridge (East Anglia): Quieter and Affordable:** Average 1-bed rent: £650–£850/month. Shorter housing waiting lists. Cambridge has a large tech/biotech sector with engineering roles. Quieter environments, strong schools, good NHS employment. Smaller East African communities but growing. Well-connected to London by train.", "**The Decision Framework:** (1) If you have a specific job offer: go where the job is. (2) If you have family or community already in a UK city: join them — community support is worth more than lower rent. (3) If you are starting fresh: prioritise areas with shorter housing waiting lists and lower rent (Leeds, Sheffield, Glasgow, medium-sized Northern towns). (4) Your dispersal area already gives you a local connection — secure housing there first, then consider moving once you are stable.", "⚠ Before leaving your dispersal area: apply for housing in your current council area AND keep your name on the list. Do NOT give up your local connection before securing stable alternative accommodation."] } }, cost: "Free (information only)", time: "Read before deciding where to settle", bring: [], links: [{ name: "Find your council (GOV.UK)", url: "https://www.gov.uk/find-local-council" }, { name: "LHA rates by area (GOV.UK)", url: "https://www.gov.uk/government/publications/local-housing-allowance-lha-rates-applicable-from-april-2024-to-march-2025" }, { name: "NACCOM refugee housing network", url: "https://naccom.org.uk" }, { name: "Numbeo cost of living (UK cities)", url: "https://www.numbeo.com/cost-of-living/country_result.jsp?country=United+Kingdom" }] },
  { id: "move-on", cat: "Housing", icon: "📦", content: { en: { title: "Move-On: Starting Your Independent Life", summary: "Just got refugee status? You have 42 days to leave asylum accommodation — check your discontinuation letter for the exact end date. Start today.", steps: ["When you receive your refugee decision letter and asylum support discontinuation notice, the move-on countdown begins immediately. The grace period is 42 days from the date on your discontinuation letter — check that letter carefully for your exact deadline. Do not wait — start today.", "IMMEDIATELY apply for Universal Credit online. The 5-week wait starts from your application date — every day of delay costs money. Citizens Advice has a national contract to help newly-recognised refugees apply, with translation available (0800 144 8848).", "Open a bank account the same day — Revolut, Monzo, Starling, or Monese all accept share code + selfie with no fixed address required.", "Apply for your National Insurance number online. You can work while waiting for it to arrive (takes 4–16 weeks).", "Contact your local council housing team immediately. Explain you are a newly recognised refugee. You have a PERMANENT local connection to this council area — this is an irrevocable legal right and key to your housing application.", "If you had your passport surrendered to the Home Office at Croydon or any UKVI office, apply for a Convention Travel Document (CTD) — £75. This is your travel document for any international travel.", "Register with a GP. Download the NHS App. No address, ID, or immigration status check is required.", "Apply for a CitizenCard (£15) for photo ID while you wait for your CTD. Apply at citizencard.com — arrives in 2–3 weeks.", "Get a free SIM card from the National Databank — 40GB/month from Vodafone, free at any library, O2 store, or partner charity.", "Ask your Jobcentre Work Coach about the Flexible Support Fund — up to £300 for deposits, transport, and work clothes.", "Your ASPEN payment card remains usable for 28 days AFTER your asylum support formally ends — keep using it during this grace period.", "If you cannot find housing by your deadline, show 'reasonable efforts' to NASS — UC application, council contact, housing search evidence. Support can be extended.", "Free furniture: British Heart Foundation shops, Freecycle.org, Facebook Marketplace 'Free' section, local refugee charities, Emmaus communities.", "After 6 months on UC: apply for a Budgeting Advance (up to £812 for furniture and household items) via your UC journal.", "⚠ Do NOT wait. Start everything on day 1. Every day of delay on Universal Credit is money lost."] } }, cost: "Free", time: "Start immediately — day 1", bring: ["Refugee decision letter", "eVisa / share code details"], links: [{ name: "Apply for UC (GOV.UK)", url: "https://www.gov.uk/universal-credit/how-to-claim" }, { name: "Citizens Advice", url: "https://www.citizensadvice.org.uk" }, { name: "Shelter — move-on help", url: "https://www.shelter.org.uk" }, { name: "Refugees at Home (spare rooms)", url: "https://www.refugeesathome.org" }, { name: "NACCOM refugee housing network", url: "https://naccom.org.uk" }, { name: "Freecycle (free furniture)", url: "https://www.freecycle.org" }] },
  { id: "refugee-integration", cat: "Settle & Stay", icon: "🌱", trustLevel: "official", content: { en: { title: "Life After Status: Your Integration Roadmap", summary: "Got refugee status? Here is everything you need to do — from day one to year five. Don't miss a deadline or a benefit you're entitled to.", steps: ["The first 42 days are critical. Your asylum support discontinuation notice gives an exact end date. Every action in this guide should start on Day 1 — not Day 30. Delay on Universal Credit costs you real money.", "Apply for Universal Credit immediately online at gov.uk/universal-credit. The mandatory 5-week wait starts from your application date — every day of delay means 5 weeks longer to your first payment. Citizens Advice (0800 144 8848) has a national contract to help newly recognised refugees apply with translation support available.", "Open a bank account the same day as your decision — Monzo, Revolut, Starling, or Monese all accept a share code plus a selfie with no fixed address required. Monese is specifically designed for newcomers and requires no credit check.", "Apply for your National Insurance number online at gov.uk/apply-national-insurance-number. You can begin work immediately while waiting for it to arrive (processing takes 4–16 weeks).", "Register with your local Jobcentre Plus and ask your Work Coach about: (1) the Flexible Support Fund — up to £300 for work clothes, transport costs, or a deposit; (2) Budgeting Advance — after 6 months on UC, you can borrow up to £812 interest-free for furniture and household essentials; (3) the New Enterprise Allowance if you want to start your own business.", "⭐ INTEGRATION LOAN — most refugees never claim this: ask your Jobcentre Work Coach to apply for a government Integration Loan. This is a free, interest-free loan of £100–£1,500 specifically for refugees. Use it for a rental deposit, furniture, work clothing, or transport. It is repaid over 2 years via small automatic deductions from your Universal Credit. You are entitled to this — make sure to ask.", "Contact your local council housing team immediately. You have a PERMANENT local connection to the council area where your asylum decision was made — this legal right cannot be lost and is the foundation of your housing application. Present yourself as newly recognised and homeless (or imminently homeless) and request an emergency assessment under the Housing Act 1996. As a refugee you are 'priority need' — the council has a legal duty to house you.", "Apply for your Convention Travel Document (CTD) — the blue refugee travel booklet — at gov.uk/travel-document. It costs £75 and takes 3–4 weeks. Without it you cannot travel internationally. If you have a valid national passport, you do not need a CTD but you still need a visa for most countries until you have ILR.", "Register with a GP and download the NHS App. As a recognised refugee you have full NHS entitlement — hospital, GP, dental, mental health, maternity, optician. No immigration status check is made at the point of care. If you are pregnant, register with a midwife immediately.", "⭐ MILESTONE AT 6 MONTHS: After 6 months in the UK, you can access publicly funded Further Education (FE) — NVQs, BTECs, functional skills, and vocational level 2/3 courses at the same subsidised rate as a UK student. After getting status you are also eligible for Student Finance England loans to attend university at home student rates (£9,250/year — NOT the £38,000+ international rate). See the Education guide for sanctuary scholarships available from 80+ universities.", "Build your credit score from month 1: register on the electoral roll (you can register as a non-citizen refugee), use a Monzo or Starling bank account regularly, take a credit builder card with a £200 limit and pay it off monthly. A good credit score in 2 years opens rental agreements, phone contracts, and eventually a mortgage.", "After 5 years as a refugee — apply for Indefinite Leave to Remain (ILR / settlement) at gov.uk/indefinite-leave-to-remain. The fee is £2,885 per person (2026 rate). ILR means you can live and work in the UK permanently without any time limit or immigration conditions.", "After 6 years — apply for British naturalisation (citizenship). You must have lived in the UK for 5 years, held ILR for 1 year, passed the Life in the UK test (£50 at an approved centre), demonstrated English language proficiency, and have no serious criminal record. The application fee is £1,330 per person (2026).", "Refugee family reunion: the family reunion visa allows recognised refugees to bring spouses and children under 18 to join them in the UK. As of early 2026 this route is temporarily closed to new applications pending a government policy review — check gov.uk/refugee-family-reunion for the current status before applying.", "⚠ Do not pay anyone to help you claim UC, apply for a NI number, or access your benefits — all of these are free. Be extremely sceptical of anyone who offers to help with immigration matters for a fee without being a registered solicitor or OISC-authorised adviser."] } }, cost: "UC free | Integration loan free | CTD £75 | ILR £2,885 | Citizenship £1,330", time: "Year 1 to year 6+", bring: ["Refugee decision letter", "eVisa / share code"], links: [{ name: "Apply for Universal Credit (GOV.UK)", url: "https://www.gov.uk/universal-credit/how-to-claim" }, { name: "Integration Loan (GOV.UK)", url: "https://www.gov.uk/integration-loan" }, { name: "Convention Travel Document (GOV.UK)", url: "https://www.gov.uk/travel-document" }, { name: "ILR — Settlement (GOV.UK)", url: "https://www.gov.uk/indefinite-leave-to-remain" }, { name: "British citizenship (GOV.UK)", url: "https://www.gov.uk/british-citizenship" }, { name: "Student Finance England", url: "https://www.gov.uk/student-finance" }, { name: "Refugee family reunion (GOV.UK)", url: "https://www.gov.uk/refugee-family-reunion" }], relatedGuideIds: ["move-on", "uc", "ilr", "esol-education", "family-reunion", "bank", "credit-score"] },
  { id: "work-rights", cat: "Work", icon: "💼", content: { en: { title: "Your Right to Work", summary: "Know your specific work rights and restrictions before starting any job.", steps: ["Refugees & ILR holders: NO restrictions. Any job, any hours.", "Skilled Worker visa: must work for the named sponsor employer only.", "Family visa: usually full work rights — verify on your eVisa.", "Student visa: max 20hrs/week during term. Full-time only in vacations.", "EU Settled Status: full unrestricted work rights.", "Give employers a Right to Work share code before your start date."] } }, cost: "Free", time: "Check before any job", bring: ["Right-to-work share code"], links: [{ name: "Prove right to work (GOV.UK)", url: "https://www.gov.uk/prove-right-to-work" }, { name: "Skilled Worker visa rules (GOV.UK)", url: "https://www.gov.uk/skilled-worker-visa" }] },
  { id: "permission-to-work", cat: "Work", icon: "🔓", content: { en: { title: "Permission to Work as an Asylum Seeker", summary: "Waited 12+ months since your asylum claim? You may already qualify — even if you've been in the inadmissibility process. ⚠ Permission to work rules for some asylum seekers are changing — check current Home Office eligibility guidance carefully.", steps: ["You can apply for Permission to Work if: (1) you have waited 12 or more months for an initial Home Office decision on your asylum claim, AND (2) the delay is not your fault (e.g. you have cooperated fully and not caused delays yourself).", "⚠️ CRITICAL — when does the 12-month clock start? It starts from the date you FIRST CLAIMED ASYLUM — NOT from when your claim moved to 'substantive consideration'. Months spent in the inadmissibility process (e.g. Rwanda/safe third country route) still count toward your 12 months.", "Inadmissibility & Permission to Work: If you claimed asylum 12+ months ago but your claim spent time in the inadmissibility process, you may ALREADY be eligible. Example: claimed 14+ months ago and in inadmissibility for 6 of those months — the 12-month clock has still been running since your original claim date. Raise this with your solicitor immediately.", "⭐ IMPORTANT CHANGE FROM 26 MARCH 2026: The eligibility rules are expanding significantly. Most asylum seekers don't know about this yet.", "BEFORE 26 March 2026: Permission to Work is restricted to jobs on the Immigration Salary List (formerly the Shortage Occupation List). This covers shortage occupations including civil engineering, nursing, teaching, coding, and other high-demand roles.", "FROM 26 March 2026 onwards: Permission to Work extends to all RQF Level 6+ (graduate-level) roles listed in Appendix Skilled Occupations. This opens up most degree-level and professional careers. Examples of newly eligible roles: Civil/structural engineer, Software developer, Project manager, Teacher, Nurse, Accountant, Social worker, Surveyor, Business analyst, and interpreter roles (e.g. NRPSI registered — nrpsi.org.uk).", "Self-employment is NOT allowed — you must be employed by a named employer. Volunteering with an organisation's permission is allowed.", "Your ARC card will be updated to show 'Permitted to Work' with the restriction category noted on the front. Show this to your employer.", "How to apply: ask your solicitor to submit the application on your behalf, or apply directly to the Home Office. There is NO application fee.", "Processing time: typically 2–8 weeks. There is no premium service — all applications are treated equally.", "⚠ Permission to work rules for some asylum seekers are changing. Public guidance is still being updated. Always verify current eligibility directly with the Home Office guidance or your solicitor before applying or accepting a job offer. If your solicitor has not discussed this change with you, raise it immediately."] } }, cost: "Free", time: "2–8 weeks processing", bring: ["ARC card", "Evidence of 12+ months wait (Home Office correspondence)", "Solicitor contact details (recommended)"], links: [{ name: "Permission to Work — GOV.UK guidance", url: "https://www.gov.uk/government/publications/handling-applications-for-permission-to-take-employment-instruction/permission-to-work-and-volunteering-for-asylum-seekers-accessible" }, { name: "Immigration Salary List (GOV.UK)", url: "https://www.gov.uk/guidance/immigration-salary-list" }, { name: "Appendix Skilled Occupations (GOV.UK)", url: "https://www.gov.uk/guidance/immigration-rules/immigration-rules-appendix-skilled-occupations" }, { name: "NRPSI — Register of Public Service Interpreters", url: "https://www.nrpsi.org.uk" }] },
  { id: "employment-rights", cat: "Work", icon: "⚖️", content: { en: { title: "Employment Rights", summary: "Every worker has legal rights from day one regardless of nationality.", steps: ["National Living Wage (21+): £12.71/hr from April 2026 (was £12.21). Illegal to pay less.", "Day one rights: 28 days paid leave, written contract, rest breaks.", "Statutory Sick Pay: £118.75/week after 4 consecutive sick days.", "After 2 years: unfair dismissal protection.", "Discrimination by race, religion, or nationality is illegal. ACAS: 0300 123 1100.", "New: Fair Work Agency launches April 2026 — stronger enforcement of wage and holiday rights."] } }, cost: "Free", time: "Know before you start", bring: [], links: [{ name: "Minimum wage rates (GOV.UK)", url: "https://www.gov.uk/national-minimum-wage-rates" }, { name: "ACAS (free workplace advice)", url: "https://www.acas.org.uk" }, { name: "Citizens Advice work rights", url: "https://www.citizensadvice.org.uk/work/" }] },
  { id: "schools", cat: "Family & Kids", icon: "🏫", content: { en: { title: "Children & Schools", summary: "All children aged 5–16 have the right to a free school place.", steps: ["Contact your local council school admissions team immediately.", "Schools CANNOT refuse children who don't speak English.", "Free EAL (English as Additional Language) support in all state schools.", "Free school meals if parents receive UC.", "Free childcare: 15–30 hours/week for ages 3–4."] } }, cost: "Free", time: "Within 20 school days", bring: ["Immunisation records (if available)"], links: [{ name: "Find your council (GOV.UK)", url: "https://www.gov.uk/find-local-council" }, { name: "Free school meals (GOV.UK)", url: "https://www.gov.uk/apply-free-school-meals" }, { name: "Free childcare (GOV.UK)", url: "https://www.gov.uk/get-childcare" }] },
  { id: "ctd", cat: "Documents & ID", icon: "🛂", content: { en: { title: "Convention Travel Document (CTD)", summary: "For recognised refugees who cannot use their home country passport.", steps: ["If you're a recognised refugee, you can apply for a CTD to travel internationally.", "Apply online. Cost: £75. Processing: usually 1–3 months.", "The CTD allows travel to most countries except your country of origin.", "⚠ NEVER travel to your country of origin — this can result in loss of refugee status.", "Since 11 March 2026, Home Office travel documents (CTD, Certificate of Travel) automatically link to your UKVI account — airlines and border staff now verify digitally. No separate letter needed.", "You can also apply for a Certificate of Travel if you have Humanitarian Protection.", "Get passport photos at any Post Office (about £12) or use a phone app."] } }, cost: "£75", time: "1–3 months", bring: ["UKVI account", "Passport-size photos", "Completed form"], links: [{ name: "Apply for travel document (GOV.UK)", url: "https://www.gov.uk/apply-home-office-travel-document" }, { name: "Passport photo rules (GOV.UK)", url: "https://www.gov.uk/photos-for-passports" }] },
  { id: "citizen-card", cat: "Documents & ID", icon: "🪪", content: { en: { title: "CitizenCard — Photo ID for £15", summary: "Government-backed PASS-accredited photo ID. No passport needed.", steps: ["A CitizenCard is a UK government-backed PASS-accredited photo ID card.", "Accepted as proof of age and identity in shops, banks, pubs, Post Offices, most organisations.", "Apply online. Cost: £15. Arrives in 2–3 weeks.", "You need: a passport-size photo, proof of address, and any document showing your date of birth.", "No passport? A Home Office decision letter + proof of address is enough.", "This is NOT an immigration document — use your share code for work/rent.", "Most affordable photo ID for anyone without a passport."] } }, cost: "£15", time: "2–3 weeks", bring: ["Photo", "Proof of address", "Any age proof"], links: [{ name: "Apply for CitizenCard", url: "https://www.citizencard.com" }, { name: "PASS scheme info", url: "https://www.pass-scheme.org.uk" }] },
  { id: "driving", cat: "Transport & Travel", icon: "🚗", content: { en: { title: "Getting a UK Driving Licence", summary: "Using foreign licences, exchanging, or starting from scratch.", steps: ["You can drive on a valid foreign licence for 12 months from when you became UK resident.", "After 12 months you MUST get a UK licence or stop driving.", "Some countries have exchange agreements — swap licence directly without a test. Check GOV.UK.", "Ethiopia is NOT a designated exchange country — you must take theory + practical tests.", "Apply for UK provisional licence: £34 online, £43 by post. Need passport/share code + proof of address.", "With a provisional: must drive with a supervising driver (full UK licence 3+ years), display L plates.", "Theory test: £23. Book online. Multiple choice + hazard perception video.", "Practical test: £62 weekday, £75 weekend. Book online.", "Driving lessons: £25–£40/hour average. Some councils fund lessons for refugees on UC.", "Car insurance is required by law. Compare at MoneySuperMarket, GoCompare, CompareTheMarket.", "International Driving Permits are NOT valid for UK residents — only for visitors.", "No documentation at all? You can still apply for a UK provisional from scratch."] } }, cost: "£34–£43 provisional", time: "Varies", bring: ["Foreign licence (if any)", "Passport or share code", "Proof of address"], links: [{ name: "Apply for provisional (GOV.UK)", url: "https://www.gov.uk/apply-first-provisional-driving-licence" }, { name: "Exchange foreign licence (GOV.UK)", url: "https://www.gov.uk/exchange-foreign-driving-licence" }, { name: "Designated countries list (GOV.UK)", url: "https://www.gov.uk/driving-nongb-licence" }, { name: "Book theory test (GOV.UK)", url: "https://www.gov.uk/book-theory-test" }, { name: "Book practical test (GOV.UK)", url: "https://www.gov.uk/book-driving-test" }] },
  { id: "proof-address", cat: "Documents & ID", icon: "📮", content: { en: { title: "Proof of Address", summary: "Get accepted proof even without a fixed home.", steps: ["Accepted documents: UC letter, HMRC letter, utility bill, bank statement (within 3 months).", "No fixed address? A letter from your hostel or support organisation works.", "Register to vote — the confirmation letter counts as proof of address.", "Royal Mail PO Box from £12 for 6 months gives you a stable mailing address."] } }, cost: "Free–£12", time: "1–5 days", bring: [], links: [{ name: "Register to vote (GOV.UK)", url: "https://www.gov.uk/register-to-vote" }, { name: "Royal Mail PO Box", url: "https://www.royalmail.com/receiving/po-box" }] },
  { id: "travel", cat: "Transport & Travel", icon: "✈️", content: { en: { title: "Travelling Abroad", summary: "How to travel now that BRPs are gone.", steps: ["Travel with your passport linked to your eVisa in UKVI. Link it BEFORE you travel.", "Since June 2025, expired BRPs are NOT accepted for travel.", "Refugees without a passport: apply for a Convention Travel Document (see CTD guide).", "⚠ Refugees: NEVER travel to your country of origin. Risk losing your status.", "Since 11 March 2026, Home Office travel documents auto-link to your UKVI account — no need to carry a separate letter.", "EU citizens: your EU passport is still valid for EU travel."] } }, cost: "CTD £75 if needed", time: "Apply 3+ months ahead", bring: ["Passport linked to UKVI"], links: [{ name: "Travel with eVisa (GOV.UK)", url: "https://www.gov.uk/evisa/travel-with-evisa" }, { name: "Apply for travel document (GOV.UK)", url: "https://www.gov.uk/apply-home-office-travel-document" }] },
  { id: "ilr", cat: "Settle & Stay", icon: "🏅", content: { en: { title: "Indefinite Leave to Remain (ILR)", summary: "Permanent UK residence — the biggest milestone. Refugees use form SET(P) which is completely FREE.", steps: ["⚠ IMPORTANT — Duration of refugee protection depends on when your claim was decided: Claims decided BEFORE 1 March 2026 → 5-year refugee leave (existing framework applies). Claims decided ON OR AFTER 2 March 2026 → 30 months (2.5 years) initial refugee leave, renewable. If you are on 30-month leave, you must renew before you can apply for ILR. Check your decision letter for the exact dates on your leave.", "Refugees: apply using form SET(P) after 5 years of continuous lawful residence. This form has NO FEE — saving you £2,885 compared to other routes. Note: if you are on the new 30-month framework, you will need to renew your leave before you can accumulate 5 years toward ILR.", "Standard routes (Skilled Worker, Family, etc.) pay £2,885. As a refugee, you are exempt from this fee.", "⚠ 2025 white paper proposals may change settlement timelines further. Check GOV.UK regularly for updates on the 30-month leave renewal process.", "Pass the Life in the UK Test (£50) — 24 questions on UK history, culture, laws. Most people pass with 2–3 weeks of free online practice.", "Prove English at level B1 — ESOL qualification, degree from a UK university, or a Secure English Language Test (SELT).", "Keep ALL documents for 5+ years: payslips, P60s, bank statements, tenancy agreements, travel records.", "After ILR, apply for British citizenship after just 1 year — requires English language, Life in the UK Test, and good character.", "Citizenship by naturalisation costs £1,500 but opens a UK passport, visa-free travel, and full civic rights.", "⚠ Avoid any absence from the UK exceeding 180 days in a year — this can break continuity and delay your ILR."] } }, cost: "FREE via SET(P) for refugees / £2,885 other routes", time: "After 5 years of residence", bring: ["5 years of documents (payslips, bank statements, tenancy)", "Passport or travel document"], links: [{ name: "ILR information (GOV.UK)", url: "https://www.gov.uk/indefinite-leave-to-remain" }, { name: "SET(P) form for refugees (GOV.UK)", url: "https://www.gov.uk/settle-in-the-uk/y/you-have-refugee-status-or-humanitarian-protection" }, { name: "Life in the UK Test", url: "https://www.gov.uk/life-in-the-uk-test" }, { name: "Apply for British citizenship (GOV.UK)", url: "https://www.gov.uk/becoming-a-british-citizen" }] },
  { id: "safety", cat: "Community", icon: "🛡", content: { en: { title: "Staying Safe", summary: "Know your rights, avoid scams, get help. The UK system has real protections for you.", steps: ["Police and immigration are SEPARATE. The police have an official firewall policy — they do NOT share information with the Home Office or immigration enforcement. You can report crimes, seek help, and be a witness without fear of immigration action.", "Police: 999 for emergencies, 101 for non-emergencies. Always call — your safety is protected by UK law regardless of your immigration status.", "Modern Slavery Helpline: 0800 0121 700 — free, 24/7, anonymous. If someone is controlling your movements, work, or money, this is illegal and they can help.", "If someone holds your passport, charges you for housing/work, or controls your bank account — this is modern slavery. Call 0800 0121 700.", "Domestic Abuse: 0808 2000 247 — free, 24/7, all languages. Safehouses are available — you will not be deported for leaving an abusive situation.", "Immigration scams: NEVER pay unregistered 'immigration consultants'. Always check the OISC register at gov.uk/find-an-immigration-adviser. Unregistered advice is a criminal offence.", "Online scams: job offers requiring payment upfront, 'fast track' visa services, requests for your share code — all scams. Report to Action Fraud: 0300 123 2040.", "Housing scams: landlords cannot demand more than 5 weeks' deposit. Never pay before viewing a property in person.", "⚠ Keep copies of all your important documents — decision letter, eVisa screenshot, NI number — in a secure app like Google Drive."] } }, cost: "Free", time: "Read now", bring: [], links: [{ name: "Find immigration adviser (GOV.UK)", url: "https://www.gov.uk/find-an-immigration-adviser" }, { name: "Modern Slavery Helpline", url: "https://www.modernslaveryhelpline.org" }, { name: "Action Fraud (report scams)", url: "https://www.actionfraud.police.uk" }] },
  { id: "community", cat: "Community", icon: "🤝", content: { en: { title: "Community & Social Life", summary: "Build connections and find support near you.", steps: ["Libraries: free internet, books, events, language cafés, computer access.", "Mosques, churches, temples, gurdwaras: community support regardless of your faith.", "Volunteering builds UK experience and references. Try do-it.org.", "Refugee Council: 0808 196 7272.", "Citizens Advice: free help with any issue you're facing."] } }, cost: "Free", time: "Start today", bring: [], links: [{ name: "Do-it volunteering", url: "https://www.do-it.org" }, { name: "Citizens Advice", url: "https://www.citizensadvice.org.uk" }, { name: "Refugee Council", url: "https://www.refugeecouncil.org.uk" }] },
  { id: "volunteering", cat: "Work", icon: "🙋", content: { en: { title: "Volunteering While Waiting for Your Decision", summary: "As an asylum seeker without permission to work, volunteering is the most important thing you can do. Start now — don't wait for your decision.", steps: ["✅ Volunteering is ALWAYS allowed — there are no restrictions on volunteering for asylum seekers. You do not need permission from the Home Office.", "The work must be genuinely voluntary: no obligation, no contract, you can stop any time. It must be for a registered charity or public body — not a private company.", "You can receive expenses only (travel, meals) — no payment or wages. Receiving payment would count as working without permission.", "Why volunteering matters: Building UK references, networks, and experience is essential for when you get your decision or Permission to Work. Volunteering with organisations in your field — engineering, healthcare, legal, construction, education, or any sector — demonstrates commitment and builds trust. UK employers hire people they know.", "Find roles: do-it.org (largest volunteering database — search by skill and location), Reach Volunteering (reachvolunteering.org.uk) specialises in skilled and professional volunteer roles.", "Construction and housing: Habitat for Humanity UK (habitatforhumanity.org.uk) — hands-on construction volunteering, perfect for civil engineering backgrounds.", "Advice and support: your local Citizens Advice bureau recruits volunteer advisers — excellent for building UK legal and welfare knowledge.", "REMA — Refugee Employability & Mentoring Alliance: specialist employability support and mentoring for refugees and asylum seekers. Contact via remauk.org.", "Mentoring: ICE (Institution of Civil Engineers) accepts volunteer mentees through their Refugee Support programme — contact ICE Refugee Support now at ice.org.uk/about-ice/what-we-do/social-mobility/refugee-support/. Do not wait for your decision.", "⭐ Every week of UK volunteering is a week of UK experience on your CV, a UK reference, and a UK network contact. Start today."] } }, cost: "Free", time: "Start immediately", bring: [], links: [{ name: "Do-it volunteering", url: "https://www.do-it.org" }, { name: "Reach Volunteering (skilled roles)", url: "https://reachvolunteering.org.uk" }, { name: "Habitat for Humanity UK (construction)", url: "https://www.habitatforhumanity.org.uk/volunteer/" }, { name: "ICE Refugee Support (engineers)", url: "https://www.ice.org.uk/about-ice/what-we-do/social-mobility/refugee-support/" }, { name: "REMA (Refugee Employability & Mentoring Alliance)", url: "https://remauk.org" }, { name: "GOV.UK — volunteering as an asylum seeker", url: "https://www.gov.uk/government/publications/handling-applications-for-permission-to-take-employment-instruction/permission-to-work-and-volunteering-for-asylum-seekers-accessible" }] },
  { id: "esol-education", cat: "Community", icon: "📚", content: { en: { title: "Free ESOL & Education While Waiting", summary: "ESOL English classes are free from day one. After 6 months in the UK, you can also access fully-funded FE college courses — NVQs, BTECs and more. Build your qualifications before your decision.", steps: ["ESOL (English for Speakers of Other Languages) classes are FREE for all asylum seekers — no waiting period, no conditions, and no need to have a decision on your claim. Start from day one.", "Your ARC card is your proof of eligibility for fee remission at any college. Show it when enrolling. You cannot be charged for ESOL if you are an asylum seeker.", "Find ESOL classes: local Further Education (FE) colleges (the biggest providers), refugee charities (e.g. Refugee Council, STAR, local groups), and your local council adult education service. Search 'ESOL classes near me' or ask your local library.", "⭐ 6-MONTH MILESTONE — FE College Courses: After 6 months lawfully in the UK, you can access publicly funded Further Education beyond ESOL. This includes NVQs, BTECs, functional skills (Maths and English), and most vocational Level 2 and Level 3 courses — at the same subsidised rate as a UK student, with no tuition fee. Show your ARC card and ask the college specifically about 'ESFA asylum seeker fee remission'. You do NOT need permission to work, a decision on your claim, or a specific ARC endorsement to enrol on these courses.", "Higher education — Sanctuary Scholarships: over 80 UK universities offer sanctuary scholarships open to asylum seekers (not only recognised refugees). Edinburgh, Warwick, Bristol, and UCL are among them — many cover full tuition plus a living bursary. Search the STAR network scholarship list at star-network.org.uk.", "Recognition of Prior Learning (RPL): if you hold a degree or professional qualification, some UK universities will assess your existing learning and award credit toward a UK qualification. This can shorten or top up a degree. Ask admissions teams specifically about RPL or credit transfer.", "Free online learning while you wait: OpenLearn (open.edu/openlearn — free, no registration), FutureLearn (futurelearn.com — many free courses), and Coursera (coursera.org — audit most courses free). Use this time to build a UK-relevant portfolio of learning.", "Google Career Certificates are free (or heavily subsidised) for eligible learners and are recognised by UK employers — Data Analytics, Project Management, UX Design, IT Support, Cybersecurity. Each takes 3–6 months online at your own pace.", "PRINCE2 Foundation: the study materials are freely available online; the exam costs ~£300 when you're ready to sit it. This qualification is widely recognised by UK project management employers.", "CSCS card theory preparation: the CITB CSCS Health, Safety and Environment test costs £26 to sit. Use the free CSCS revision app to prepare now so you can sit it as soon as you have the right to work.", "⭐ Building qualifications, certificates, and learning evidence while waiting transforms your CV and demonstrates commitment to UK employers. Start now — none of this requires a work permit."] } }, cost: "Free (ESOL and FE courses) — exam fees apply for some certifications", time: "ESOL: start immediately. FE courses: from 6 months in the UK", bring: ["ARC card (for fee remission at college)"], links: [{ name: "Find ESOL classes (GOV.UK)", url: "https://www.gov.uk/find-a-community-support-group-or-organisation" }, { name: "OpenLearn (free courses)", url: "https://www.open.edu/openlearn/" }, { name: "FutureLearn", url: "https://www.futurelearn.com" }, { name: "Google Career Certificates", url: "https://grow.google/intl/uk_ALL/google-career-certificates/" }, { name: "STAR — University Sanctuary Scholarships", url: "https://star-network.org.uk/access-to-university/scholarships/list/" }, { name: "Coursera (audit free)", url: "https://www.coursera.org" }] },
  { id: "community-interpreting", cat: "Training", icon: "🗣️", trustLevel: "official", content: { en: { title: "Community Interpreting: Train Now, Work Later", summary: "If you speak two languages and your English is strong, community interpreting is one of the most practical career paths available while waiting. Training is studying — not working — so no right to work is needed. You can start your Level 2 qualification from 6 months after arriving.", steps: ["Community interpreting means helping people communicate in healthcare, housing, social services, schools, and council settings — not conference or legal interpreting. Community interpreters work with GPs, housing officers, social workers, and councils. It is in high demand across the UK and especially in areas with diverse communities like Norfolk.", "Training is NOT working. You do not need the right to work (permission to work) to study community interpreting. The course is classed as education. This is one of the very few practical career-track activities available to asylum seekers before a decision.", "⭐ WEA Level 2 Certificate in Community Interpreting — this is the top recommended starting point. The WEA (Workers' Educational Association) runs this course online, making it accessible from anywhere in England including Norwich. It is fully funded through the Adult Skills Fund for eligible learners. Cost: free if you have been in the UK for 6 months or more. Duration: approximately 24–30 weeks part-time. Find it at: wea.org.uk/find-a-course and search 'community interpreting'.", "East Coast College (Great Yarmouth / Lowestoft) also offers community-facing interpreting and language support courses. As a Norfolk resident, check their current provision at eastcoast.ac.uk.", "What the Level 2 covers: introduction to interpreting theory and practice, consecutive interpreting technique (listen → take notes → interpret), professional ethics and boundaries, impartiality and accuracy, role of the interpreter in different settings (health, housing, legal, education), and a practical assessment.", "Language pairs in demand in Norfolk: Tigrinya, Amharic, Arabic, Kurdish (Kurmanji), Somali, Pashto, Dari, Albanian, Romanian, Polish. If one of these is your first language and your English is strong, you are in an excellent position.", "After Level 2: progress to Level 3 Community Interpreting (1 year), then consider the DPSI — Diploma in Public Service Interpreting — awarded by the Chartered Institute of Linguists (CIOL). The DPSI qualifies you for courts, police, NHS, and immigration tribunals. Qualified DPSI interpreters earn £25–£50 per hour as self-employed contractors.", "Register on the NRPSI (National Register of Public Service Interpreters) after qualifying — this is the standard professional register that public sector bodies use to find interpreters. nrpsi.org.uk", "If you are refused while on the course: the 'mid-year continuity' provision under ESFA rules normally allows you to finish the specific learning aim (the course or unit) you started while eligible, even if your status changes during the course. This is not automatic — speak to your college or WEA administrator immediately if your situation changes. Do not abandon the course without checking.", "While waiting for your Level 2 to complete, you can volunteer as an informal language supporter through the British Red Cross Norwich (redcross.org.uk/get-involved/volunteer), New Routes Integration Norfolk (nrinorfolk.co.uk), or The Bridge Plus+ (Norfolk refugee services). Volunteering counts as relevant experience for your CV and for the NRPSI portfolio.", "Practical preparation now (no qualification needed): do-it.org (national volunteering platform) has community language volunteer roles. Sign up, add your languages, and start building a portfolio. This is directly relevant experience for the NRPSI registration portfolio.", "After getting status and Right to Work: register as self-employed on HMRC's website (free, takes 20 minutes), set up a simple invoice template, and contact Norfolk County Council translation services, NHS Norfolk and Waveney ICB, and Norfolk Constabulary interpreter rosters directly. Many public bodies maintain their own approved supplier lists."] } }, cost: "Free (Adult Skills Fund — asylum seekers 6 months+ in UK are eligible)", time: "Level 2: 24–30 weeks part-time | Level 3: 1 year | DPSI: 1–2 years", bring: ["ARC card (for fee remission / eligibility evidence)", "Evidence of your language pair — you will be informally assessed at enrolment"], links: [{ name: "WEA — Find a Community Interpreting Course", url: "https://www.wea.org.uk/find-a-course" }, { name: "East Coast College (Norfolk)", url: "https://www.eastcoast.ac.uk" }, { name: "NRPSI — National Register of Public Service Interpreters", url: "https://www.nrpsi.org.uk" }, { name: "DPSI — Diploma in Public Service Interpreting (CIOL)", url: "https://www.ciol.org.uk/dpsi" }, { name: "Do-it — Community Language Volunteer Roles", url: "https://do-it.org" }, { name: "New Routes Integration Norfolk", url: "https://www.nrinorfolk.co.uk" }], relatedGuideIds: ["advanced-learner", "esol-education", "permission-to-work", "volunteering", "work-rights"] },
  { id: "advanced-learner", cat: "Training", icon: "📖", content: { en: { title: "Strong English? Your Real Learning Path", summary: "If your English is already strong — IELTS 6.5 or above, Functional Skills Level 2, or equivalent — generic ESOL is not the right starting point for you. This guide maps a practical, progression-focused route through the English adult learning system while you wait for a decision.", steps: ["The English adult learning system has several layers. The most useful for you are: (1) Functional Skills Level 2 in Maths and English — equivalent to GCSE grade 4/C, required by many UK employers and as a condition of some funded courses; (2) Level 2 and Level 3 vocational qualifications — BTECs, City & Guilds, NVQs in specific fields; (3) degree-level — but this requires a Student Finance loan or scholarship; and (4) professional qualifications — AAT, ACCA, CIMA, ICE, APM, etc.", "⭐ Check if you need Functional Skills Level 2 first. Even with IELTS 7.5 or an overseas degree, some funded courses require Functional Skills Level 2 Maths and/or English as a pre-condition. Take an initial assessment at any FE college — it is free and takes 1–2 hours. If you already meet Level 2 standard, you will get a certificate quickly (weeks). Norfolk Adult Learning offers these assessments too.", "⭐ TOP PRIORITY — Community Interpreting (if you speak a second language). See the Community Interpreting guide. This is the single best use of your 6-month waiting period if you are bilingual. Training does not require the right to work.", "⭐ SECOND PRIORITY — AAT Level 2 Certificate in Bookkeeping. The AAT (Association of Accounting Technicians) qualification is the UK's most widely recognised entry route into finance, accounting, and bookkeeping. City College Norwich (ccn.ac.uk) offers the AAT Level 2 and Level 3. It is funded through the Adult Skills Fund (free after 6 months in the UK). AAT Level 2 takes approximately 6 months part-time. It opens doors to bookkeeper, accounts assistant, and payroll roles — all of which are eligible for Right to Work once you have it. Your MBA background means you will progress through AAT faster than most learners.", "⭐ THIRD PRIORITY — Norfolk Adult Learning (norfolk.gov.uk/education-and-learning). Norfolk County Council's Adult Learning service runs funded short courses in: digital skills (spreadsheets, Microsoft 365, email, online safety); business enterprise; employability skills (CV writing, interview technique, UK workplace culture); and community engagement. These are free or heavily subsidised for eligible learners. Very practical for building a UK-relevant CV while waiting.", "City College Norwich (CCN) — ccn.ac.uk — is the main FE college for Norwich. In addition to AAT, it offers: BTEC Level 3 Business; Computing and IT Level 3; Construction and Engineering (relevant for your Civil Engineering background); Access to HE diplomas; and professional short courses. Ask specifically about Adult Skills Fund / ESFA fee remission with your ARC card.", "WEA — wea.org.uk — runs online funded courses including community interpreting, digital skills, and wellbeing. Accessible from anywhere in England. You do not need to travel.", "Volunteering in parallel: volunteer at New Routes Integration Norfolk (nrinorfolk.co.uk), British Red Cross Norwich (redcross.org.uk), or The Bridge Plus+. This builds a UK CV, references, and demonstrates integration. It also keeps you informed about job opportunities and training that is not widely advertised.", "If you are refused while on a funded course: the ESFA 'mid-year continuity' provision normally allows you to complete the specific learning aim (unit or full qualification) you started while eligible. Speak to your college Student Services team immediately — do NOT abandon the course without checking. This is a formal ESFA funding rule, not a discretionary favour.", "After getting status — Free Courses for Jobs and Skills Bootcamps: once you have Refugee Leave (or any other settled/pre-settled status), you can access Free Courses for Jobs — a government scheme covering full Level 3 qualifications in high-demand areas (accounting, construction, digital, childcare, engineering). Skills Bootcamps offer 16-week intensive training with a guaranteed job interview. Search both at gov.uk/free-courses-for-jobs.", "Qualification bridging for your overseas credentials: UK ENIC (enic.org.uk) provides a Statement of Comparability for your BSc Civil Engineering and MBA — cost £49 each, accepted by employers and universities. Apply as soon as you have copies of your transcripts. Breaking Barriers (breaking-barriers.co.uk) supports professional re-accreditation for engineers and business professionals — free for refugees, highly relevant for ICE Chartership and CMI recognition.", "⚠ What NOT to do: do not spend your waiting period on ESOL if your English is already Level 2+ standard — that time is better spent on vocational or professional qualifications. Do not pay for courses that are available free through the Adult Skills Fund. Do not sign up for unaccredited online certificates that UK employers do not recognise — stick to regulated qualifications (Ofqual-regulated, AAT, CIOL, City & Guilds, BTEC, Pearson, OCR)."] } }, cost: "Free (Adult Skills Fund — eligible after 6 months lawfully in the UK)", time: "Functional Skills Level 2: weeks | AAT Level 2: 6 months | Level 3 qualifications: 1 year", bring: ["ARC card (for fee remission at college)", "Any previous qualification certificates or transcripts", "IELTS certificate or evidence of English level"], links: [{ name: "Norfolk Adult Learning (Norfolk County Council)", url: "https://www.norfolk.gov.uk/education-and-learning" }, { name: "City College Norwich", url: "https://www.ccn.ac.uk" }, { name: "AAT — Accounting Qualifications", url: "https://www.aat.org.uk" }, { name: "WEA — Find a Course", url: "https://www.wea.org.uk/find-a-course" }, { name: "Free Courses for Jobs (GOV.UK)", url: "https://www.gov.uk/free-courses-for-jobs" }, { name: "Skills Bootcamps (GOV.UK)", url: "https://www.gov.uk/guidance/skills-bootcamps" }, { name: "New Routes Integration Norfolk", url: "https://www.nrinorfolk.co.uk" }, { name: "Breaking Barriers Reaccreditation", url: "https://breaking-barriers.co.uk/refugee-support/reaccreditation/" }, { name: "UK ENIC Statement of Comparability", url: "https://www.enic.org.uk/Qualifications/SOC/Default.aspx" }], relatedGuideIds: ["community-interpreting", "esol-education", "re-qualify", "volunteering", "permission-to-work"] },
  { id: "re-qualify", cat: "Work", icon: "🎓", content: { en: { title: "Recognise Your Qualifications", summary: "Your overseas degree and professional credentials can be recognised in the UK — often for free.", steps: ["UK ENIC (formerly UK NARIC): get a Statement of Comparability for your overseas degree — £49. Accepted by employers, universities, and professional bodies across the UK.", "Refugees without original documents: email refugee@ecctis.com — reduced-cost or waived assessment available. Your institution may also provide a replacement certificate.", "Breaking Barriers Reaccreditation Programme: free professional assessment, mentoring, and liaison with UK regulatory bodies. Covers engineering, healthcare, teaching, law, finance, and trades. Apply at breaking-barriers.co.uk.", "RefuAid interest-free loans: up to £10,000 to cover exam fees, registration costs, course materials for re-qualifying. Zero interest, repayable once you're earning. Access via RefuAid's partner network at refuaid.org.", "Civil Engineers (BSc/BEng/MEng): ICE Refugee Support programme — free mentoring and chartership (MICE → CEng) pathway. The Engineering Council registers all UK engineers. Target CEng status within 3–5 years for £50K–£80K+ salaries.", "For an MBA: APM (Association for Project Management) and CMI (Chartered Management Institute) recognise business qualifications. A Chartered Manager Degree Apprenticeship is a free route to CMI Level 6.", "Doctors: GMC registration + PLAB Part 1 & 2 exams. Many NHS trusts fund OSCE exams for overseas doctors. Breaking Barriers healthcare track provides mentors.", "Nurses: NMC registration + OSCE (Objective Structured Clinical Examination) for overseas-trained nurses. NHS trusts commonly fund this.", "Teachers: qualified teacher status via School Direct or Assessment Only route. UK ENIC recognition helps. Contact the DfE and Refugee Education UK.", "Lawyers: Solicitors Qualification Examination (SQE) is the new route. Some law firms and charities (e.g. Refugee Legal Aid) run bursary programmes.", "⚠ Never pay unregistered agencies to 'certify' your qualifications. Use only UK ENIC, your UK professional body, or GOV.UK."] } }, cost: "£49 UK ENIC + professional body fees (often funded)", time: "Weeks to years depending on profession", bring: ["Degree certificate (original or copy)", "Academic transcripts", "Professional registration certificates"], links: [{ name: "UK ENIC Statement of Comparability", url: "https://www.enic.org.uk/Qualifications/SOC/Default.aspx" }, { name: "Breaking Barriers Reaccreditation", url: "https://breaking-barriers.co.uk/refugee-support/reaccreditation/" }, { name: "RefuAid Interest-Free Loans", url: "https://www.refuaid.org" }, { name: "ICE Refugee Support (Engineers)", url: "https://www.ice.org.uk/about-ice/what-we-do/social-mobility/refugee-support/" }, { name: "Engineering Council (UK)", url: "https://www.engc.org.uk" }] },
  { id: "family-reunion", cat: "Family & Kids", icon: "👨‍👩‍👧", content: { en: { title: "Family Reunion", summary: "Bring your immediate family to the UK. Know the current rules.", steps: ["⚠ The refugee family reunion route is CLOSED to new applications pending Government review. Applications submitted before 3pm on 4 September 2025 may still be processed — contact your solicitor to check the status of any pending application.", "While the route is closed: your spouse/partner and children under 18 must apply through standard family visa routes. These cost £1,538+ per person.", "A refugee family reunion application was previously free — the closure is pending review. Monitor gov.uk and the Refugee Council for updates on when a revised route may reopen.", "RefuAid interest-free loans can help cover family reunion costs including legal fees and travel expenses. Contact via refuaid.org.", "Legal aid is available for refugee family reunion cases — contact a Legal Aid solicitor via the Law Centres Network (lawcentres.org.uk).", "Family tracing help: the Refugee Council (0808 196 7272) and the British Red Cross (redcross.org.uk) both provide family tracing services.", "Keep evidence of your family relationship: photos, messages, marriage/birth certificates (or sworn statements if documents are unavailable).", "⚠ NEVER travel to your country of origin to collect family members — this risks your refugee status.", "⚠ The family reunion route is closed pending review — it has not been permanently abolished. Prepare your documents now so you are ready to apply as soon as a revised route is announced."] } }, cost: "Free (refugee route) / £1,538+ per person (standard visa route)", time: "3–12+ months once route reopens", bring: ["Proof of family relationship", "Evidence of refugee status"], links: [{ name: "Refugee family reunion (GOV.UK)", url: "https://www.gov.uk/uk-family-visa" }, { name: "Refugee Council — family reunion", url: "https://www.refugeecouncil.org.uk/information/refugee-asylum-facts/family-reunion/" }, { name: "Law Centres Network (legal aid)", url: "https://www.lawcentres.org.uk" }, { name: "RefuAid loans", url: "https://www.refuaid.org" }] },
  { id: "legal-help", cat: "Asylum Process", icon: "⚖️", content: { en: { title: "Free Legal Advice", summary: "Free legal help is available for immigration, housing, employment, and more. You have the right to legal aid — this guide shows you where to find it.", steps: ["Legal aid is FREE for most immigration and asylum cases. You do NOT need to pay a solicitor for asylum appeals, bail hearings, or immigration tribunal hearings. Check if you qualify at gov.uk/legal-aid.", "Find an OISC-registered immigration adviser using the official GOV.UK search (gov.uk/find-an-immigration-adviser). OISC-registered advisers are regulated and trustworthy. Never use an unregulated 'immigration consultant' — it is illegal to charge for immigration advice unless registered.", "Law Centres: free specialist legal advice on employment, housing, welfare benefits, and immigration. Find your nearest at lawcentres.org.uk.", "Citizens Advice: free advice on any legal issue — benefits, housing, employment, debt, family. Walk in or call 0800 144 8848. Translation services available.", "Shelter: free housing legal advice online, by phone (0808 800 4444), or in person. Specialist housing lawyers at no cost.", "Asylum Aid: free specialist legal help for complex asylum cases, particularly for women and unaccompanied children — asylumaid.org.uk.", "UNHCR UK: if you believe your rights are being violated in the asylum process, contact the UNHCR at unhcr.org/uk.", "Employment rights: ACAS (Advisory, Conciliation and Arbitration Service) provides free employment rights advice — acas.org.uk or 0300 123 1100. Free for all workers.", "Housing legal rights: if you are being illegally evicted, your landlord has changed the locks, or you are being harassed, call Shelter immediately (0808 800 4444). These are criminal offences.", "⚠ Never pay anyone claiming to offer immigration advice who is not OISC-registered or a solicitor. Fake immigration advisers are common and charge thousands for work that should be free. If something goes wrong, report to the OISC at oisc.gov.uk."] } }, cost: "Free", time: "Legal aid available immediately", bring: ["Any letters or documents relating to your case"], links: [{ name: "Check if you qualify for legal aid (GOV.UK)", url: "https://www.gov.uk/legal-aid" }, { name: "Find OISC immigration adviser (GOV.UK)", url: "https://www.gov.uk/find-an-immigration-adviser" }, { name: "Law Centres Network", url: "https://www.lawcentres.org.uk" }, { name: "Citizens Advice", url: "https://www.citizensadvice.org.uk" }, { name: "Shelter — housing legal help", url: "https://www.shelter.org.uk" }, { name: "Asylum Aid", url: "https://www.asylumaid.org.uk" }, { name: "ACAS — employment rights", url: "https://www.acas.org.uk" }] },
  { id: "aspen-card", cat: "Asylum Process", icon: "💳", content: { en: { title: "Asylum Support & Your ASPEN Card", summary: "How Section 95 support works, what your ASPEN card covers, and what to do if things go wrong.", steps: ["Section 95 support is provided by the Home Office to asylum seekers who would otherwise be destitute. It has two parts: accommodation (provided directly) and a weekly cash payment loaded onto your ASPEN card.", "The standard Section 95 rate for 2025/26 is £49.18 per week for a single adult. Higher rates apply if you have dependent children. This is your entire weekly living allowance.", "Payments are loaded onto your ASPEN card weekly. The day depends on your area — most areas pay on Mondays, some on Wednesdays. Check your support letter for your area's payment day.", "Your ASPEN card works like a Visa prepaid card. You can use it anywhere that accepts Visa — supermarkets, pharmacies, clothing shops, and transport. You do NOT need to explain what it is.", "Older ASPEN cards CANNOT be used at ATMs to withdraw cash. Newer cards may allow limited cashback at supermarket tills (usually £10–£20). If you need cash, ask the cashier for cashback when buying something.", "There is no way to top up your ASPEN card. The amount loaded is fixed by the Home Office. If you feel the amount is wrong, contact Migrant Help on 0808 8010 503 (free helpline).", "If you lose your ASPEN card, report it immediately to Migrant Help: 0808 8010 503 (free, 24/7). A replacement will be issued. Do not delay — your payments may be suspended until the new card arrives.", "Your ASPEN card is intended to cover: food and drink, clothing, toiletries and personal hygiene items, and travel within your local reporting area. It does NOT cover rent — your accommodation is provided separately by the Home Office as part of Section 95 support.", "Section 4 support is different. If your asylum claim has been refused but you cannot safely return to your home country, you may qualify for Section 4 support. Section 4 provides accommodation and an Azure card (similar to ASPEN) instead of cash. Contact Migrant Help to apply.", "Maternity payment: if you are pregnant, you can apply for a one-off £300 maternity grant in addition to your weekly support. Apply through Migrant Help (0808 8010 503) — this is not automatic, you must ask.", "⚠ Never give your ASPEN card or its PIN to anyone else. Never pay anyone to 'manage' your ASPEN payments. If anyone asks, it is a scam."] } }, cost: "Free (provided by Home Office)", time: "Weekly payments while claim is active", bring: ["ASPEN card", "Home Office support letter"], links: [{ name: "Asylum support (GOV.UK)", url: "https://www.gov.uk/asylum-support" }, { name: "Section 4 support (GOV.UK)", url: "https://www.gov.uk/asylum-support/section-4-support" }, { name: "Migrant Help (0808 8010 503)", url: "https://www.migranthelp.org" }, { name: "Asylum support rates (GOV.UK)", url: "https://www.gov.uk/government/publications/asylum-support-asylum-seekers-bank-accounts-and-nass-35" }] },
  { id: "women-support", cat: "Community", icon: "♀️", content: { en: { title: "Support for Women & Girls", summary: "Specialist services, career paths, safety, and rights for refugee women and girls in the UK.", steps: ["Women for Refugee Women: free support, legal advice, campaigning, community for women asylum seekers and refugees. Helpline: 020 7250 1239 (womenforrefugeewomen.org.uk).", "Asylum Aid: specialist legal help for women with complex asylum claims. Free, based in London, national reach.", "Refugee Women Connect (Birmingham): employment support, social activities, training specifically for refugee women.", "Survivors of sexual and gender-based violence: Freedom from Torture provides specialist free therapy — referral via GP or self-referral at freedomfromtorture.org.", "Domestic abuse: call 0808 2000 247 (free, 24/7, all languages). Safehouses are available. You WILL NOT be deported or have your case affected for leaving an abusive situation.", "Maternity care is free on the NHS from the moment you arrive — register with a GP or midwife immediately. The Maternity Action helpline advises on rights: 0808 802 0029.", "Child benefit: claim from your refugee grant date (max 3 months back). If you are a lone parent, you automatically have priority need for housing.", "Career paths with strong demand for women from refugee backgrounds: Social Work (excellent progression, good pay from day one), Healthcare (Band 2 HCA: start within weeks), Childcare and Early Years Education, Teaching Assistants, Translation & Interpreting (rare language speakers are paid well).", "Free vocational training targeted at women: ESOL with childcare (many colleges offer this together), Care Certificate (care home funded), Skills Bootcamps (government-funded, open to all genders).", "Safety planning: if you feel unsafe, contact the police on 101 (non-emergency) or 999 (emergency). Police do NOT report to immigration enforcement. Your safety always comes first.", "Girls aged 16–18: dedicated support through the Prince's Trust (free education, employment and life-skills programmes) and Catch22 (mentoring and training for young women).", "⚠ Female Genital Mutilation (FGM): illegal in the UK. Anyone threatened with FGM can call the NSPCC FGM helpline: 0800 028 3550 (free, 24/7). You will be protected, not prosecuted."] } }, cost: "Free", time: "Access services immediately", bring: [], links: [{ name: "Women for Refugee Women", url: "https://www.womenforrefugeewomen.org.uk" }, { name: "Freedom from Torture", url: "https://www.freedomfromtorture.org" }, { name: "Domestic Abuse Helpline", url: "https://www.nationaldahelpline.org.uk" }, { name: "Maternity Action", url: "https://www.maternityaction.org.uk" }, { name: "Prince's Trust (young women 16–30)", url: "https://www.princes-trust.org.uk" }, { name: "FGM NSPCC Helpline", url: "https://www.nspcc.org.uk/what-is-child-abuse/types-of-abuse/female-genital-mutilation-fgm/" }] },
  { id: "vehicle-ownership", cat: "Transport & Travel", icon: "🚗", content: { en: { title: "Buying a Vehicle in the UK", summary: "How to buy a car, e-bike, or e-scooter in the UK — insurance, road tax, MOT, and where to buy.", steps: ["CARS — USED vs NEW: Most immigrants buy a used car first. Used cars cost £2,000–£8,000 for a reliable hatchback (Ford Fiesta, Vauxhall Corsa, Toyota Yaris). New cars from £14,000+. Electric cars (EVs) are cheaper to run but cost more to buy — grants may be available via the Plug-in Vehicle Grant.", "WHERE TO BUY A CAR: Dealerships (new and used, regulated, warranty included), private sellers (cheaper but no warranty — buyer beware), online platforms: AutoTrader (autotrader.co.uk), CarGurus (cargurus.co.uk), eBay Motors, and Facebook Marketplace. Always check for outstanding finance using HPI Check (hpicheck.com) before buying privately — around £20 and essential.", "CAR INSURANCE (MANDATORY): You CANNOT legally drive without insurance. Third-party insurance is the minimum legal requirement. Comprehensive insurance (strongly recommended) covers damage to your own car too. Compare quotes on MoneySuperMarket, GoCompare, or CompareTheMarket. New drivers with no UK insurance history pay more — typically £1,000–£3,000/year. Building a no-claims bonus reduces costs each year.", "ROAD TAX (Vehicle Excise Duty — VED): Required for all vehicles driven or parked on public roads. Check and pay online at gov.uk/vehicle-tax. Cost depends on CO2 emissions and vehicle age. Electric cars: currently £0–£195/year. Older petrol/diesel cars: up to £695/year. Untaxed vehicles face fines of up to £1,000.", "MOT TEST: All cars over 3 years old need an annual MOT roadworthiness test (~£55). Book at any garage displaying the blue MOT sign. The test checks brakes, tyres, lights, emissions, and steering. Fail: the car cannot be driven on public roads until it passes. Check your MOT status at check-mot-status.service.gov.uk.", "VEHICLE REGISTRATION (DVLA): When you buy a car, the seller must tell the DVLA and give you the V5C logbook (vehicle registration document). Update the registered keeper details on gov.uk/change-name-address-v5c within 2–5 days of purchase. If no V5C: apply for a duplicate at the DVLA for £25.", "E-BIKES (Electric Bicycles): Legal to ride on roads and cycle paths with no licence, no insurance, and no road tax. Must be pedal-assisted (not throttle-only above 6km/h), max speed 15.5mph assisted, max motor 250W. Buy from Halfords, Evans Cycles, Decathlon, or online from Ribble, Canyon, or Cube. Cost: £500–£3,000. Highly recommended for city commuting.", "ELECTRIC SCOOTERS (E-SCOOTERS) — IMPORTANT LEGAL RESTRICTIONS: Private e-scooters are ILLEGAL to ride on public roads, pavements, and cycle paths in the UK as of 2025. They are only legal on private land with the landowner's permission. Only rental e-scooters (operated by schemes like Lime, Voi, Tier) are legal on roads in specific trial areas. If caught riding a private e-scooter on the road: fine, penalty points, and potential seizure of the scooter.", "MOTORCYCLES AND MOPEDS: You need at minimum a provisional licence and Compulsory Basic Training (CBT — approximately £130, one day). After CBT you can ride a 125cc moped/motorcycle. Full motorcycle licence requires theory + practical tests. Insurance and road tax apply.", "COSTS SUMMARY: Budget for insurance (£1,000–£2,500/year for new drivers), road tax (£0–£695/year), MOT (~£55/year), fuel (petrol ~£70–£120/month for an average commuter), plus maintenance. Second-hand cars under £3,000 often have higher repair costs — budget at least £500/year."] } }, cost: "From £2,000 (used car) + insurance + road tax", time: "Can buy same day", bring: ["Valid driving licence", "Insurance already arranged", "Payment (debit card, cash, or finance arranged in advance)"], links: [{ name: "Check a car's MOT history (GOV.UK)", url: "https://www.check-mot-status.service.gov.uk" }, { name: "Pay vehicle tax (GOV.UK)", url: "https://www.gov.uk/vehicle-tax" }, { name: "AutoTrader — used car search", url: "https://www.autotrader.co.uk" }, { name: "HPI Check — outstanding finance check", url: "https://www.hpicheck.com" }, { name: "Compare car insurance (MoneySuperMarket)", url: "https://www.moneysupermarket.com/car-insurance/" }, { name: "E-scooter laws (GOV.UK)", url: "https://www.gov.uk/electric-scooters-rules-for-using-them" }, { name: "DVLA — update vehicle registration", url: "https://www.gov.uk/change-name-address-v5c" }] },
  { id: "interpreting", cat: "Work", icon: "🗣️", content: { en: { title: "Becoming a Community Interpreter", summary: "Speakers of rare languages like Amharic can build a viable UK career as community or public service interpreters. Here is how to qualify, register, and find work.", steps: ["WHY INTERPRETING IS A REALISTIC CAREER FOR REFUGEE LANGUAGE SPEAKERS: The UK public sector relies heavily on community interpreters for healthcare (NHS), courts, police, social services, and immigration. Amharic (Ethiopia) and Tigrinya (Eritrea) interpreters are in significant demand due to large East African asylum-seeking populations. Rare language interpreters can command £25–£45/hour and work flexibly.", "ROUTES TO BECOMING AN INTERPRETER — no formal degree is required to start, but qualifications improve your rates and access to better contracts:", "1. DPSI (Diploma in Public Service Interpreting) — the main UK qualification for legal, health, or local government interpreting. Level 6 qualification. Courses offered by London Metropolitan University, University of Westminster, and other colleges. Costs approximately £600–£1,500 depending on provider. Exams in English + your language pair.", "2. CIOL Qualifications (Chartered Institute of Linguists) — the other main qualification route. Offers Certificate in Community Interpreting (£300–£800) and higher diplomas. Check ciol.org.uk for Amharic-pair exam availability.", "3. NRPSI (National Register of Public Service Interpreters) — the official UK register. Registration costs around £95/year. NRPSI registration is required by many NHS trusts and courts. Eligibility: DPSI or equivalent qualification + experience. Check nrpsi.org.uk.", "4. LanguageLine, thebigword, Capita Translation, and Vandu Language Services are the largest agencies supplying interpreters to NHS, courts, and police. Register directly as a freelance interpreter. Most accept applications from qualified interpreters without a DPSI if you have significant experience.", "SELF-REFERRAL ROUTE (before qualification): Many community organisations, refugee charities, and social services use unqualified community interpreters on a voluntary or low-paid basis. This builds experience and references. Contact local refugee charities, law centres, and NHS trusts directly.", "RATES AND EARNINGS: Phone/video interpreting typically pays £15–£22/hour. Face-to-face interpreting in courts, hospitals, and police stations pays £25–£45/hour with a minimum call-out fee (often 2 hours). Top interpreters with NRPSI registration in rare languages earn £30,000–£50,000/year working full-time.", "PRACTICAL REQUIREMENTS: Strong written and spoken English (CEFR B2 minimum, C1 recommended), complete fluency in your source language, clear knowledge of subject-specific vocabulary (medical, legal, or social care terminology in both languages), a DBS (Disclosure and Barring Service) check (agencies arrange this — free for volunteers, ~£18 for employed), and reliable broadband for remote interpreting.", "ASYLUM SEEKERS: Note that interpreting counts as work — you cannot be paid for interpreting without Permission to Work. Volunteering as an interpreter (no payment) is always allowed and builds crucial experience and references.", "⭐ ACTION STEPS: (1) Register on LanguageLine Solutions, thebigword, and Vandu Language Services now. (2) Book a DPSI short course. (3) Join the NRPSI mailing list. (4) Contact your local NHS Trust or law centre and ask if they need Amharic/Tigrinya interpreters."] } }, cost: "DPSI ~£600–£1,500 | NRPSI registration ~£95/year", time: "3–12 months to qualify", bring: ["English language evidence (ESOL certificate, degree, etc.)", "CV showing language background", "DBS check (agencies arrange this)"], links: [{ name: "NRPSI — National Register of Public Service Interpreters", url: "https://www.nrpsi.org.uk" }, { name: "CIOL — Chartered Institute of Linguists", url: "https://www.ciol.org.uk" }, { name: "LanguageLine Solutions — register as interpreter", url: "https://www.languageline.com/en-gb/interpreter-resources" }, { name: "thebigword — interpreter registration", url: "https://www.thebigword.com/interpreting-jobs" }, { name: "Capita Translation & Interpreting", url: "https://www.capitatranslationinterpreting.com/interpreter-registration/" }, { name: "ITI — Institute of Translation & Interpreting", url: "https://www.iti.org.uk" }] },
  { id: "investing", cat: "Money", icon: "📊", content: { en: { title: "Starting to Invest in the UK", summary: "Once you have 3–6 months of savings, growing your money becomes possible. The UK has one of the world's best tax-free savings structures.", steps: ["**Before investing, build a safety buffer:** Keep 3–6 months of living expenses in an easy-access savings account (Marcus by Goldman Sachs, Chip, or Monzo Savings Pots currently offer 4–5% interest). Never invest money you might need within 5 years.", "**The ISA — Your Most Powerful Tax Advantage:** An Individual Savings Account (ISA) lets you save or invest up to £20,000 per year completely tax-free — no capital gains tax and no income tax on returns. This advantage does not exist in most countries. Any UK resident with a valid visa can open an ISA.", "**Lifetime ISA (LISA) — The Government Adds 25% Free:** If you are 18–39 and saving for your first UK home or for retirement, a Lifetime ISA is exceptional. Put in up to £4,000/year and the government adds a 25% bonus (up to £1,000/year — free money). Use it ONLY for a first home purchase or retirement at age 60+. There is a 25% penalty for withdrawing for other reasons.", "**Stocks & Shares ISA — Long-Term Growth:** Once you have an emergency fund, a Stocks & Shares ISA invested in low-cost global index funds (Vanguard FTSE All-World, HSBC Global Strategy Adventurous) grows significantly over 5–10+ years. Historical global index fund returns: 7–10% per year on average. Available via Vanguard Investor, Freetrade, or Trading 212 — all regulated, all free to open.", "**Premium Bonds — Zero Risk, Tax-Free Prizes:** NS&I Premium Bonds are 100% government-backed. Instead of interest, your money is entered into a monthly prize draw. Prizes from £25 to £1 million — all tax-free. You can withdraw anytime. Minimum £25. Effective return equivalent to approximately 4% annually. Ideal for money you may need in under 5 years.", "**Start Small — Pound-Cost Averaging:** Invest a fixed amount monthly (even £25) regardless of market conditions. This 'pound-cost averaging' removes the pressure of timing the market and builds discipline. Most platforms allow automated monthly deposits from your bank account.", "**Who Can Invest:** Any UK resident with a bank account can open an ISA. You do NOT need UK citizenship or settled status — most visa types allow investing. Check your eVisa conditions for any investment restrictions (very rare).", "**The 3-Year Rule also applies to investment mortgages:** Just as with personal loans, most UK mortgage lenders require 3 years of UK address history. Once you have 3+ years, a Stocks & Shares ISA down-payment strategy becomes possible.", "**Tax on investments OUTSIDE an ISA:** Capital Gains Tax allowance is £3,000/year (2025/26). Dividends above £500/year are taxed. This is why the ISA wrapper is so powerful — all growth inside is completely tax-free regardless of amount.", "**⚠ Avoid Cryptocurrency and 'Quick Returns' Schemes:** These are specifically targeted at immigrant communities via social media and WhatsApp groups. 80% of day traders lose money. HMRC tracks crypto gains. Stick to low-cost regulated index funds inside an ISA for the first 5+ years."] } }, cost: "From £1/month", time: "Long-term — 5+ years for real results", bring: [], links: [{ name: "ISA guide (GOV.UK)", url: "https://www.gov.uk/individual-savings-accounts" }, { name: "Lifetime ISA (GOV.UK)", url: "https://www.gov.uk/lifetime-isa" }, { name: "Vanguard Investor UK", url: "https://www.vanguardinvestor.co.uk" }, { name: "Premium Bonds (NS&I)", url: "https://www.nsandi.com/products/premium-bonds" }, { name: "MoneySavingExpert ISA guide", url: "https://www.moneysavingexpert.com/savings/stocks-shares-isas/" }] },
  { id: "uk-rules", cat: "Money", icon: "📜", content: { en: { title: "UK Rules Every New Arrival Must Know", summary: "Laws and rules that catch new arrivals off-guard. Ignorance is not a legal defence — these are the ones that matter most.", steps: ["**The National Lottery & Gambling:** Gambling is legal and heavily regulated in the UK. The National Lottery (£2/ticket, Saturday and Wednesday draws) and EuroMillions (£2.50, Tuesday and Friday) are the official state lotteries. Any UK resident aged 18+ can play at licensed retailers or at national-lottery.co.uk. **Winnings are 100% tax-free in the UK.** There are no immigration restrictions on lottery prizes. Fixed-odds betting shops (Ladbrokes, Betfred, William Hill) are on every high street and are legal.", "**⚠ Warning on Gambling:** Gambling companies verify your age and identity using your address and bank details. Budget-conscious gamblers: the UK Gambling Commission found the average person who gambles loses £400–£1,000 per year. Set a strict personal limit. Gambling addiction helpline: GamCare 0808 8020 133 (free, confidential, 24/7).", "**Driving Law:** You can drive on a valid foreign licence for up to 12 months after becoming a UK resident. After that, you must convert to a UK licence by passing the theory test (£23) and practical test (£62 weekday). Speed limits: 20–30mph in towns, 60mph on single carriageways, 70mph on motorways. Drink-driving limit: 80mg alcohol per 100ml blood (Scotland: stricter at 50mg). Using a mobile phone while driving: £200 fine and 6 penalty points — even at traffic lights.", "**Drug Laws:** All illegal drugs including cannabis are Class A, B, or C offences. Cannabis is Class B — possession: up to 5 years prison, supply: up to 14 years. Despite being legal in some countries, cannabis is treated as a criminal matter in the UK. Drug convictions can affect future visa applications and naturalisation for British citizenship.", "**Knife Law — Zero Tolerance:** It is illegal to carry any knife with a blade longer than 3 inches (7.5cm) in a public place without a valid reason (a kitchen knife in packaging from a shop is usually fine). Penalty: up to 4 years in prison. This is actively enforced, especially in cities. Even a penknife in your pocket can be an offence.", "**Age Limits:** The age of consent is 16. The legal drinking age is 18 — buying alcohol for someone under 18 is an offence. Most shops operate 'Challenge 25' — they will ask for ID if you look under 25. Accepted ID: passport, UKVI share code screen, CitizenCard, or driving licence.", "**Benefits Fraud:** Claiming benefits you are not entitled to is a criminal offence. This includes: not reporting a change in household income, not reporting a partner moving in, and working without declaring it. Penalties include repayment of all funds, fines up to £5,000, and a criminal record which permanently affects future visa applications.", "**Your Right to Strike and Join a Union:** UK workers have the right to strike and join trade unions. No employer can legally dismiss you for participating in a lawfully organised strike. Trade unions (Unison, Unite, GMB) provide free legal advice, support during disciplinary procedures, and collective bargaining. Many new arrivals from countries where this is suppressed don't know this right exists.", "**Scam Awareness:** HMRC, the Home Office, and UK police will NEVER ask you to pay by bank transfer, gift cards, or cryptocurrency. If someone contacts you claiming to be from these organisations and asks for payment — hang up immediately and call the real number from the official GOV.UK website. Scams specifically target immigrant communities. Report all scams to Action Fraud at actionfraud.police.uk or 0300 123 2040."] } }, cost: "Free to read", time: "Read now — applies immediately", bring: [], links: [{ name: "National Lottery", url: "https://www.national-lottery.co.uk" }, { name: "Driving on a foreign licence (GOV.UK)", url: "https://www.gov.uk/driving-nongb-licence" }, { name: "GamCare — gambling support", url: "https://www.gamcare.org.uk" }, { name: "Knife law (GOV.UK)", url: "https://www.gov.uk/buying-carrying-knives" }, { name: "Report a scam (Action Fraud)", url: "https://www.actionfraud.police.uk" }] },
  { id: "uk-enic", cat: "Work", icon: "🎓", content: { en: { title: "Get Your Overseas Degree Recognised (UK ENIC)", summary: "Your overseas degree or professional qualification is real. UK ENIC issues a Statement of Comparability that tells UK employers, universities, and professional bodies exactly how it maps to the UK system — unlocking jobs, professional membership, and study routes.", steps: ["**Why this matters:** UK employers and professional bodies (RICS, ICE, Engineering Council, NMC, HCPC) cannot assess overseas qualifications directly. A UK ENIC Statement of Comparability provides an official, standardised UK comparison. Without it, many employers simply cannot process your application. With it, your CV becomes immediately legible to the UK market.", "**What UK ENIC produces:** A Statement of Comparability listing the approximate UK equivalent level of your qualification (e.g. 'comparable to a UK Bachelor's degree at RQF Level 6' or 'comparable to a UK Master's degree at RQF Level 7'). This is accepted by UK universities for entry and by most professional bodies for membership assessment.", "**Cost:** £49 per qualification at enic.org.uk. Both a BSc and an MBA can be assessed separately — each is a separate application.", "**Asylum Seeker Fee Waiver:** If you are currently an asylum seeker and cannot afford the fee, email **refugee@ecctis.com** (ECCTIS is the official organisation that runs UK ENIC). Request the Refugee and Asylum Seeker Fee Waiver. You will need to provide evidence of your asylum claim (ARC card or Home Office support letter). The waiver can reduce or eliminate the fee entirely.", "**What you need to apply:** (1) Original or certified copies of your qualification certificates and transcripts. (2) An official English translation if documents are not in English — contact your issuing university directly, many provide English transcripts on request. (3) Your passport or ID document. (4) Payment (£49 per qualification, or fee waiver if eligible).", "**Ethiopian degrees — specific guidance:** Degrees from Addis Ababa University, Jimma University, Hawassa University, and other recognised Ethiopian universities are well-known to UK ENIC and are routinely assessed. A BSc in Civil Engineering from Addis Ababa University is typically assessed as comparable to a UK Bachelor's (Honours) degree at RQF Level 6. An MBA from Addis Ababa University is typically assessed as comparable to a UK Master's degree at RQF Level 7.", "**Processing time:** Standard service: 15 working days. Express service: 5 working days (additional £30). The final statement is issued as a PDF — download and save multiple copies.", "**How to use the statement on your CV:** Add a line such as: 'BSc Civil Engineering, Addis Ababa University, 2018 (UK ENIC: RQF Level 6 equivalent)'. Submit a copy with job applications. Send to RICS, ICE, or other professional bodies when applying for membership.", "**Professional body notes:** RICS requires ENIC for overseas qualifications — email join@rics.org after getting your statement. ICE (Institution of Civil Engineers) accepts ENIC comparability statements — email through the ICE Refugee Support programme. The Engineering Council uses ENIC as the starting document for overseas-qualified engineers.", "**⭐ Do this in week 1.** The ENIC process takes 15 working days minimum. Starting immediately means your statement arrives before you need it for job applications. Every professional pivot option — RICS, ICE, Data Analyst, Project Management — benefits from having this document."] } }, cost: "£49 per qualification (fee waiver available for asylum seekers — email refugee@ecctis.com)", time: "15 working days (standard) or 5 days (express +£30)", bring: ["Original certificates and transcripts", "English translations (if not already in English)", "Passport or ID"], links: [{ name: "UK ENIC — apply online", url: "https://www.enic.org.uk/Qualifications/SOC/Default.aspx" }, { name: "RICS — overseas membership routes", url: "https://www.rics.org/surveying-profession/join-rics/international-routes-to-membership/" }, { name: "ICE Refugee Support", url: "https://www.ice.org.uk/about-ice/what-we-do/social-mobility/refugee-support/" }, { name: "RefuAid — interest-free loans for professionals", url: "https://www.refuaid.org" }] },
  { id: "uk-cv", cat: "Work", icon: "📝", content: { en: { title: "Write a UK-Standard CV", summary: "A UK CV is different from CVs in Ethiopia, the Middle East, and most of Africa and Asia. Knowing the rules prevents your application being discarded before it is read.", steps: ["**The UK CV is NOT the same as an American résumé or an African application form.** Key differences: UK CVs include no photo, no date of birth, no marital status, no nationality, no religion. Adding these details flags unfamiliarity with UK norms and gives employers information they are legally not supposed to consider under the Equality Act 2010.", "**Standard UK CV length:** 2 pages maximum for most roles. 1 page for junior or entry-level roles. 3 pages only for senior academic or technical roles with extensive publications. If your CV is currently 3–5 pages, it needs cutting — UK recruiters spend 6–8 seconds on initial screening.", "**CV structure (top to bottom):** (1) Name and contact details — name, phone (UK number), professional email, LinkedIn URL, city only (no full address). (2) Professional Profile — 3–5 lines summarising your career and what you offer. (3) Work Experience — most recent first. For each role: Job Title | Employer | City | Month/Year–Month/Year, then 3–5 bullet points of achievements. (4) Education — most recent first, with UK ENIC comparability if obtained. (5) Skills — technical skills, software, languages. (6) Certifications. (7) References — write 'Available on request' or omit entirely.", "**The achievement bullet point — the most important technique:** UK CVs distinguish between duties (what you were supposed to do) and achievements (what you actually delivered). Formula: Action Verb + What You Did + Quantified Result. Weak: 'Responsible for property valuations'. Strong: 'Delivered 150+ commercial and residential valuations annually for a portfolio of ETB 2.8B (~£50M), supporting lending decisions across 5 regional branches'.", "**Translating overseas experience for UK readers:** UK employers may not know overseas organisations. Add brief context: instead of 'Awash Bank', write 'Awash Bank (one of Ethiopia's largest private commercial banks, 450+ branches nationwide)'.", "**Gaps in employment:** UK employers are generally understanding about gaps caused by asylum or forced migration. A brief professional explanation is fine — e.g. 'Career break — relocated to the UK following grant of refugee status (March 2026)'. Never leave unexplained multi-year gaps.", "**ATS (Applicant Tracking Systems):** Most large UK employers filter CVs through automated software before a human reads them. To pass: use standard headings (Work Experience, Education, Skills), include keywords from the job description naturally, avoid tables, columns, text boxes, and unusual fonts. Use a simple single-column Word (.docx) format.", "**UK English spelling:** Use UK English throughout: organisation (not organization), recognised (not recognized), programme (not program), labour (not labor). Small signals matter.", "**Cover letters:** Most UK jobs require a short cover letter (250–350 words). Be specific to the role — state the job title, explain how your experience matches the listed requirements, and say why you want that specific employer. Generic cover letters are worse than none.", "**LinkedIn is essential for professional roles.** A complete profile is expected. Turn on 'Open to Work'. Connect with everyone you meet professionally. Follow target employers. Many UK recruiters proactively search LinkedIn — your profile is your second CV.", "**Free CV help:** Breaking Barriers (breaking-barriers.co.uk) and the Refugee Employment Network (refugeeemploymentnetwork.org) both offer free CV reviews and one-to-one CV coaching for refugees. Use them — professional review measurably increases interview rates."] } }, cost: "Free (free tools and charities available)", time: "Allow 4–8 hours to write your first draft; 1–2 weeks for review and refinement", bring: ["Certificates and transcripts (with dates)", "Dates of previous employment (start and end month/year)", "Names and contact details of previous managers (for references)", "UK ENIC statement if obtained"], links: [{ name: "Breaking Barriers — free CV support", url: "https://breaking-barriers.co.uk/refugee-support/employment/" }, { name: "Refugee Employment Network — CV help", url: "https://refugeeemploymentnetwork.org/" }, { name: "Reed CV template (free)", url: "https://www.reed.co.uk/career-advice/cv-template/" }, { name: "National Careers Service — CV sections (GOV.UK)", url: "https://nationalcareers.service.gov.uk/get-a-job/cv-sections" }, { name: "Citizens Advice — finding a job", url: "https://www.citizensadvice.org.uk/work/finding-a-job/" }] },
  // ─── Business & Money ──────────────────────────────────────────
  { id: "sole-trader", cat: "Business & Money", icon: "🧾", trustLevel: "official", content: { en: { title: "Becoming a Sole Trader", summary: "How to register as self-employed with HMRC, what taxes you owe, and what records to keep. The simplest way to start your own business in the UK.", steps: ["Register as self-employed with HMRC as soon as you start trading — you must do this by 5 October in your second year of business. Go to gov.uk/set-up-sole-trader. You will need your National Insurance number. Registration is free.", "As a sole trader you pay Income Tax on profits above the Personal Allowance (£12,570/year in 2025/26) and National Insurance (Class 2: £3.45/week; Class 4: 9% on profits between £12,570–£50,270). Use HMRC's self-assessment tax return each January for the previous tax year.", "Keep records of all your income and expenses. You are legally required to keep these for at least 5 years after the January submission deadline. A simple spreadsheet works. Free tools: FreeAgent (free via NatWest/RBS), Wave Accounting.", "You can claim business expenses against your tax bill: mileage (45p/mile for the first 10,000 miles), phone bills, equipment, home office costs. Using the simplified expenses guide on GOV.UK saves accountant fees.", "Open a separate bank account for your business income and expenses — this isn't legally required as a sole trader but makes tax returns much easier and looks more professional to clients.", "If your turnover exceeds £90,000/year you must register for VAT. Below that threshold, VAT registration is optional (but can be beneficial if your clients are VAT-registered businesses).", "You are personally liable for any business debts as a sole trader — your personal savings and assets can be used to pay them. If your business involves significant risk, consider forming a limited company instead."] } }, cost: "Free to register", time: "30 min online", bring: ["National Insurance number", "Business name (or your own name)"], links: [{ name: "Register as self-employed — GOV.UK", url: "https://www.gov.uk/set-up-sole-trader" }, { name: "Self Assessment tax returns — GOV.UK", url: "https://www.gov.uk/self-assessment-tax-returns" }, { name: "Simplified expenses — GOV.UK", url: "https://www.gov.uk/simpler-income-tax-simplified-expenses" }, { name: "Business expenses — GOV.UK", url: "https://www.gov.uk/expenses-if-youre-self-employed" }], relatedGuideIds: ["limited-company", "business-records", "home-business", "tax", "ni"] },
  { id: "limited-company", cat: "Business & Money", icon: "🏢", trustLevel: "official", content: { en: { title: "Setting Up a Limited Company", summary: "How to incorporate a UK limited company through Companies House, what it costs, and your legal duties as a director.", steps: ["Incorporate online through Companies House at gov.uk/register-your-company. It costs £50 (online, paid by card) and usually takes 24 hours. You will need a company name, registered UK address, at least one director and one shareholder, and a Standard Industrial Classification (SIC) code.", "A limited company is a separate legal entity from you. This means the company — not you personally — is liable for business debts (limited liability). Directors are still personally liable for wrongful trading or fraud.", "As a director you must file: a Confirmation Statement (£34/year), annual statutory accounts, and a Corporation Tax return with HMRC (Corporation Tax rate: 19–25% of profits depending on size).", "Many small company owners pay themselves a low salary (around £12,570/year to use the personal allowance tax-free) and take the rest as dividends, which are taxed at lower rates than income.", "All limited companies must verify their identity with Companies House from 2025. Directors must complete identity verification via the GOV.UK One Login system before or shortly after incorporation — see the Companies House ID Verification guide.", "A limited company must have a Registered Address — a real UK address that can receive official mail. Many accountants offer a registered address service for around £50–£100/year if you work from home.", "Accounting costs: FreeAgent (free via NatWest/RBS), Xero (~£15/month), or QuickBooks. A good accountant for a small company costs £500–£1,500/year and is often worth it for year-end accounts and Corporation Tax filing."] } }, cost: "£50 (Companies House registration)", time: "24 hours once submitted", bring: ["Company name", "UK registered address", "NI number (for identity verification)"], links: [{ name: "Register a company — Companies House", url: "https://www.gov.uk/register-your-company" }, { name: "Corporation Tax — GOV.UK", url: "https://www.gov.uk/corporation-tax" }, { name: "Directors' responsibilities — GOV.UK", url: "https://www.gov.uk/guidance/being-a-company-director" }, { name: "Companies House ID verification", url: "https://www.gov.uk/guidance/verify-your-identity-for-companies-house" }], relatedGuideIds: ["sole-trader", "companies-house-id", "business-records", "home-business", "tax"] },
  { id: "home-business", cat: "Business & Money", icon: "🏠", trustLevel: "official", content: { en: { title: "Running a Business from Home", summary: "What to check before using your home address as your business base — planning, insurance, tenancy, and tax implications.", steps: ["Check your tenancy agreement: most rental contracts require written landlord permission before running a business from the property. Some prohibit business clients visiting the address. Tell your landlord in writing before you start.", "Check your home insurance: standard home insurance usually does not cover business equipment or liability for visiting clients. You may need a business insurance add-on (from ~£5–£10/month) or a separate policy.", "Planning permission: if customers regularly visit, you want to put up signage, or you convert part of your home to business-only use, you may need planning permission from your local council.", "Council Tax: if part of your home is used exclusively for business (never for personal use), that room may attract business rates. Mixed use — a room used for both work and personal purposes — is usually fine. Check with your local council.", "Expenses: claim a proportion of your home costs (rent, utilities, broadband) as business expenses. Use HMRC's simplified home working rate (£6/week flat rate) or calculate the actual proportion of your home used for work.", "Privacy: your home address becomes publicly visible on Companies House if it is the registered address of a limited company. Use an accountant's registered address service to protect your privacy."] } }, cost: "Free (check insurance costs separately)", time: "Check before trading", links: [{ name: "Working from home expenses — HMRC", url: "https://www.gov.uk/expenses-if-you-work-from-home" }, { name: "Run a business from home — GOV.UK", url: "https://www.gov.uk/run-business-from-home" }], relatedGuideIds: ["sole-trader", "limited-company", "business-records"] },
  { id: "business-records", cat: "Business & Money", icon: "📒", trustLevel: "official", content: { en: { title: "Business Records & Bookkeeping", summary: "What records you must keep as a self-employed person or director, how long to keep them, and free tools to make bookkeeping simple.", steps: ["As a sole trader you must keep records of all business income and expenses for at least 5 years after the 31 January self-assessment deadline. That means records for the 2024/25 tax year must be kept until 31 January 2031.", "As a limited company director you must keep accounting records for at least 6 years from the end of the last financial year they relate to. Companies House and HMRC have separate filing deadlines — missing either results in automatic fines.", "What to keep: all invoices (issued and received), bank statements, receipts for business purchases, mileage logs if claiming car expenses, payroll records, and VAT records if VAT-registered.", "Free tools: Wave Accounting (web-based, free), FreeAgent (free via NatWest/RBS business account), and HMRC's list of Making Tax Digital-compliant apps. Photographing receipts with cloud backup is acceptable.", "HMRC can investigate tax returns up to 4 years after filing (20 years if fraud is suspected). If you cannot produce records when asked, HMRC will estimate your income — usually in their favour.", "Separate your personal and business finances from day one: Monzo Business, Starling Business, and Tide offer free or low-cost business accounts. This single step makes bookkeeping dramatically simpler."] } }, cost: "Free (tools available at no cost)", time: "Ongoing", links: [{ name: "Self-employed records — GOV.UK", url: "https://www.gov.uk/self-employed-records" }, { name: "Company accounting records — GOV.UK", url: "https://www.gov.uk/running-a-limited-company/company-and-accounting-records" }, { name: "Making Tax Digital — HMRC", url: "https://www.gov.uk/guidance/use-making-tax-digital-for-income-tax" }], relatedGuideIds: ["sole-trader", "limited-company", "tax"] },
  { id: "companies-house-id", cat: "Business & Money", icon: "🏛️", trustLevel: "official", content: { en: { title: "Companies House Identity Verification", summary: "From 2025, all company directors and People with Significant Control (PSCs) must verify their identity with Companies House. Here is how.", steps: ["Companies House introduced mandatory identity verification under the Economic Crime and Corporate Transparency Act 2023. All current directors and PSCs must verify, and new ones must verify before or shortly after appointment.", "Verify through GOV.UK One Login (gov.uk/sign-in). You will need: a valid photo ID (UK driving licence, UK passport, or biometric residence permit / eVisa), and your National Insurance number or a smartphone for face verification.", "Identity verification is free. Once verified, you receive a Companies House personal code linked to your GOV.UK One Login. Submit this code on Companies House filings.", "If your photo ID is not UK-issued, you may need an Authorised Corporate Service Provider (ACSP) — such as a solicitor or accountant — to verify on your behalf. ACSPs register with Companies House and charge for this service.", "Failure to verify when required means you cannot be formally appointed as a director or PSC. Companies House can annotate the public register to show verification has not been completed.", "Once verified, your details are stored securely — you do not need to re-verify each time you set up a new company or are appointed to another board."] } }, cost: "Free (via GOV.UK One Login)", time: "15–30 minutes", bring: ["Valid photo ID (UK driving licence, passport, or BRP/eVisa)", "National Insurance number"], links: [{ name: "Verify your identity for Companies House", url: "https://www.gov.uk/guidance/verify-your-identity-for-companies-house" }, { name: "GOV.UK One Login", url: "https://www.gov.uk/sign-in" }, { name: "Economic Crime Act — Companies House factsheets", url: "https://www.gov.uk/government/publications/economic-crime-and-corporate-transparency-act-2023-factsheets" }], relatedGuideIds: ["limited-company", "cic"] },
  { id: "cic", cat: "Business & Money", icon: "🤲", trustLevel: "official", content: { en: { title: "Community Interest Company (CIC)", summary: "A CIC is a special type of limited company for social enterprises that want to benefit their community. Here is what makes it different and how to set one up.", steps: ["A Community Interest Company (CIC) is a limited company that passes the 'community interest test' — it must benefit a defined community, not just its shareholders. Profits must be used for community benefit rather than freely distributed.", "CICs are regulated by the CIC Regulator (part of Companies House) alongside normal Companies House requirements. You must file a CIC Report annually alongside statutory accounts.", "To incorporate, complete the CIC36 form in addition to normal Companies House incorporation. The CIC Regulator reviews and approves applications — this usually adds 2–5 working days on top of normal incorporation time.", "CICs can be limited by shares (like a normal limited company) or limited by guarantee (like most charities). Unlike charities, CICs can pay directors a reasonable salary and retain some profit — but profits cannot be freely distributed to shareholders.", "Many grant funders (local councils, the National Lottery, charitable trusts) accept CICs as grant recipients. However, some funders still require full charity status. You can convert a CIC to a registered charity if needed.", "The CIC Association (cicassociation.org.uk) offers free advice calls and resources. The GOV.UK CIC guidance is comprehensive and free."] } }, cost: "£27 (CIC36 form) + £50 (Companies House incorporation) = £77 total", time: "3–7 days", bring: ["Company name", "UK registered address", "Description of community purpose"], links: [{ name: "Set up a CIC — GOV.UK", url: "https://www.gov.uk/set-up-a-social-enterprise" }, { name: "Office of the CIC Regulator", url: "https://www.gov.uk/government/organisations/office-of-the-regulator-of-community-interest-companies" }, { name: "CIC Association", url: "https://cicassociation.org.uk" }], relatedGuideIds: ["limited-company", "companies-house-id"] },
  { id: "before-you-invest", cat: "Business & Money", icon: "⚠️", trustLevel: "official", warnings: ["Never invest money you cannot afford to lose", "Crypto is not protected by the FSCS or Financial Ombudsman"], content: { en: { title: "Before You Invest Any Money", summary: "The essential safety checks to do before putting any money into an investment, crypto, business opportunity, or scheme — and how to spot scams.", steps: ["Check the FCA register first: any firm or person that wants you to invest money must be authorised by the Financial Conduct Authority. Check register.fca.org.uk before sending a single penny. It is free and takes 60 seconds.", "Warning signs of a scam: you were cold-called or messaged on WhatsApp/Telegram; returns are 'guaranteed' or unusually high; you are told to act quickly or keep it secret; payment is requested via cryptocurrency or overseas bank transfer.", "Check the FCA Warning List at fca.org.uk/consumers/warning-list-firms — it shows firms currently under investigation or known to be operating illegally in the UK.", "Clone firm fraud: scammers copy the name, logo, and FRN of real authorised firms. Always verify contact details via the FCA register directly — not via details given to you by the person contacting you.", "Crypto investments are NOT protected by the Financial Ombudsman Service or FSCS. If you lose crypto, there is usually no recovery route. Only use crypto platforms registered with the FCA.", "If already scammed: report to Action Fraud (0300 123 2040 or actionfraud.police.uk) immediately. Contact your bank — they can sometimes reverse payments. Report the firm to the FCA.", "Safe starting points: NS&I Premium Bonds (100% UK government-backed, max £50,000), cash ISAs (up to £20,000/year, tax-free interest), or Stocks and Shares ISAs through FCA-authorised platforms such as Vanguard, Trading 212, or Freetrade."] } }, cost: "Free to check", time: "Before you invest anything", links: [{ name: "FCA Financial Services Register", url: "https://register.fca.org.uk" }, { name: "FCA Warning List", url: "https://www.fca.org.uk/consumers/warning-list-firms" }, { name: "ScamSmart — FCA", url: "https://www.fca.org.uk/scamsmart" }, { name: "Report a scam — Action Fraud", url: "https://www.actionfraud.police.uk" }, { name: "MoneyHelper — investment scams", url: "https://www.moneyhelper.org.uk/en/savings/types-of-savings/investment-scams" }], relatedGuideIds: ["investing", "scam-warnings", "bank"] },
  { id: "scam-warnings", cat: "Business & Money", icon: "🚨", trustLevel: "official", warnings: ["Never pay for a free government service", "Immigration advisers must be OISC-regulated or a solicitor"], content: { en: { title: "Scam Warnings: What Not to Pay For", summary: "Things that are free in the UK that scammers charge migrants for — plus how to protect yourself and what to do if you have already paid.", steps: ["Right to Work checks are FREE. Your employer uses your share code from gov.uk/view-prove-immigration-status. No company should charge you to 'process' or 'verify' your immigration status — if they do, it is a scam.", "NHS treatment is FREE for refugees, asylum seekers, and most migrants with valid leave. You should never pay for GP registration, A&E treatment, or maternity care. Prescriptions, some dental work, and optician charges apply only to those not on qualifying benefits.", "National Insurance numbers are FREE to apply for via HMRC. Any website or person charging you to apply for or 'register' an NI number is running a scam.", "Universal Credit is applied for free at gov.uk/apply-universal-credit. Citizens Advice and Jobcentre Plus staff help you apply at no cost. 'Benefit processing agents' who charge fees are unnecessary.", "Immigration advice must come from someone regulated by the OISC (Office of the Immigration Services Commissioner) or a qualified solicitor. Unregulated 'consultants' often charge thousands for advice that Citizens Advice, the Refugee Council, or law centres provide free.", "Visa processing scams: scammers pose as UKVI or the Home Office demanding payment to 'expedite' or 'secure' your visa. The Home Office will NEVER request payment via bank transfer or cryptocurrency. All official fees are paid through gov.uk.", "If you have been scammed: report to Action Fraud (0300 123 2040), contact your bank to try to reverse the payment, and report immigration fraud at gov.uk/report-immigration-fraud."] } }, cost: "Free to check", time: "Before you pay anyone", links: [{ name: "Report immigration fraud — GOV.UK", url: "https://www.gov.uk/report-immigration-fraud" }, { name: "Find a regulated immigration adviser — OISC", url: "https://www.gov.uk/find-an-immigration-adviser" }, { name: "Report a scam — Action Fraud", url: "https://www.actionfraud.police.uk" }, { name: "NHS entitlements — migrant health guide", url: "https://www.gov.uk/guidance/nhs-entitlements-migrant-health-guide" }, { name: "MoneyHelper — scams", url: "https://www.moneyhelper.org.uk/en/everyday-money/scams" }], relatedGuideIds: ["before-you-invest", "safety", "legal-help"] },
  // ─── Training ──────────────────────────────────────────────────
  { id: "get-qualified-first", cat: "Training", icon: "🎯", trustLevel: "official", sourceLabel: "official-guidance", lastVerified: "March 2026", warnings: ["Getting a trainer card before the worker card is not possible in most regulated sectors — awarding bodies will reject the application", "Companies selling 'fast-track' trainer cards or 'shortcut' NVQs outside official routes are not operating within the regulated system — CSCS explicitly warns against unofficial intermediaries"], content: { en: { title: "Get Qualified First — My UK Career Route", summary: "Before training others, providing services, or running a course, I need my own UK credentials in place. This maps the correct order: confirm right to work → establish English level → get sector qualification → build UK experience → consider trainer or business routes later.", steps: ["**Step 1 — Confirm my right to work.** Everything else depends on this. My UKVI eVisa share code proves my current right to work status to any UK employer. Without it, no employer can legally take me on. Check and generate my share code at gov.uk/view-prove-immigration-status. If I am an asylum seeker: I can only work if my ARC card says 'Permitted to Work' on the front, and only in jobs on the Immigration Salary List. There is no shortcut around this step.", "**Step 2 — Establish my English level.** Most UK sector qualifications require Functional English at Level 1 or Level 2. Trade cards (CSCS, SIA, DVSA theory tests) require that I can read safety notices and answer test questions in English. If my English needs development, free ESOL classes start from day one — this is not a delay, it is the foundation everything else is built on.", "**Step 3 — Get my overseas qualifications recognised (if applicable).** If I hold a degree or professional certificate from overseas, UK ENIC gives me a Statement of Comparability (£49, or free for refugees via refugee@ecctis.com). Some sector awarding bodies (CITB, CSCS, NOCN, City & Guilds) accept recognised overseas experience to reduce training time or allow direct entry. Do not skip this step — it can save months and significant money.", "**Step 4 — Get the foundational sector qualification or card.** This is the occupational-level card or cert I need to WORK in my sector. The trainer, supervisor, or specialist card comes after this, not before it. Key examples by sector: (Construction) CSCS Green Card = CITB Health, Safety & Environment test (£22.50) + NVQ Level 2 or QCF Level 2 Award in Construction Skills — required before any progression to Skilled Worker, Supervisor, or Trainer card. (Driving instruction) DVSA ADI Part 1 (theory), Part 2 (driving ability), Part 3 (instructional ability) — must complete all three parts as a trainee before supervising learners independently. (Security) SIA Door Supervisor or Security Guard licence = NOCN/City & Guilds Level 2 Award + SIA application (£220). (Health and social care) Care Certificate (15 standards) then NVQ Level 2 in Health and Social Care. (HGV/LGV driving) DVSA Category C theory, hazard perception, and practical test. The sector body — CSCS, DVSA, SIA, NMC — sets the minimum operative qualification before any trainer or specialist route is available.", "**Step 5 — Get documented UK work experience in the sector.** Most trainer, assessor, and advanced qualifications explicitly require recent, documented UK work experience at operative level. This cannot be skipped or substituted with overseas experience alone. (CSCS) Construction Trainer/Tutor cards require NVQ Level 3+ and demonstrated industry competence — without a UK employment record this is not achievable. (ADI) Roles supervising other trainee instructors require holding a full ADI licence for at least 2 years. (AET — Award in Education and Training) requires active and observed teaching practice, not just a course certificate. Get into the first employed role as soon as the foundational card is in hand.", "**Step 6 — Build a continuous professional development (CPD) record from day one.** Keep a log of: dates and descriptions of training completed, employer references and job titles, HSE certificates, sector-specific refreshers (e.g., CSCS Site Safety Plus courses, SIA first aid renewal). This CPD record is exactly what awarding bodies check when I apply for advanced qualifications or trainer routes later. Most regulated sector licences (CSCS, SIA, ADI) require periodic renewal with evidence of CPD.", "**LATER — Trainer or assessor qualification (after operative experience is established).** Once I have documented occupational competence at the right level, I can consider: Award in Education and Training (AET, Level 3 — minimum entry for teaching in Further Education or running short courses), Certificate in Education and Training (CET, Level 4 — for regular FE teaching roles), CAVA (Level 3 Certificate in Assessing Vocational Achievement — for workplace assessors and NVQ verifiers), CSCS Supervisor or Manager Card (requires SMSTS — Site Management Safety Training Scheme, run by CITB, 5 days, approx. £600–£800). These qualification routes are only open after I can demonstrate competency at operative level.", "**LATER — Business or provider route (after an established work identity).** Starting as a sole trader, limited company, or registered training provider in a regulated sector requires all of the above PLUS: professional indemnity and public liability insurance, regulatory registration where applicable (Ofsted for training providers offering publicly funded courses, DVSA for approved driving instructor schools, FCA for financial services), a minimum period of documented practice that satisfies the regulator, and in many cases an inspection or quality-assurance process. Register the company after the qualifications are in place — the business depends on the credentials, not the other way around.", "⚠️ **Verify every qualification route at the official body.** CSCS cards: cscs.uk.com. DVSA ADI: gov.uk/become-approved-driving-instructor. SIA: sia.homeoffice.gov.uk. CITB: citb.co.uk. NOCN qualifications: nocn.org.uk. National Careers Service: nationalcareers.service.gov.uk. If a company or individual is offering me a route that does not appear on these official sites, that route is not valid."] } }, cost: "Varies: CSCS test £22.50 + NVQ (often funded); ADI tests £62–£111 each; SIA application £220; AET Level 3 approx. £300–£700", time: "3–24 months to operative level depending on sector and prior experience", bring: ["Right to work share code (gov.uk/view-prove-immigration-status)", "Overseas qualification certificates (for UK ENIC recognition)", "English language evidence (if required by awarding body)"], links: [{ name: "National Careers Service — Explore Careers", url: "https://nationalcareers.service.gov.uk/explore-careers" }, { name: "CSCS card types — official CSCS site", url: "https://www.cscs.uk.com/card-types/" }, { name: "CITB — construction training and qualifications", url: "https://www.citb.co.uk/courses-and-qualifications/" }, { name: "Become an approved driving instructor (ADI) — DVSA", url: "https://www.gov.uk/become-approved-driving-instructor" }, { name: "SIA licence application — official SIA", url: "https://www.sia.homeoffice.gov.uk/Pages/licensing.aspx" }, { name: "Award in Education and Training (AET) — NOCN", url: "https://www.nocn.org.uk/qualifications/award-in-education-and-training-level-3/" }], relatedGuideIds: ["work-rights", "re-qualify", "esol-education", "advanced-learner", "sole-trader"] },
  // ─── Housing ───────────────────────────────────────────────────
  { id: "housing-brokerage", cat: "Housing", icon: "🤝", content: { en: { title: "Helping Others Find Housing (Community Support)", summary: "Many immigrants informally help community members find housing. Here is how to do it legally, ethically, and safely — and what to avoid.", steps: ["COMMUNITY HOUSING SUPPORT IS REAL AND VALUABLE: Many Ethiopian, Eritrean, and other East African community members rely on trusted community contacts to help them find accommodation. This is a genuine and important role — connecting people who speak no English with landlords, housing charities, and support services. Done correctly, it is legal and ethical.", "WHAT YOU CAN LEGALLY DO AS AN INFORMAL HOUSING HELPER: (1) Share information about available rooms and houses with community members. (2) Help translate between a landlord and a potential tenant. (3) Accompany someone to viewings and help them communicate. (4) Help them understand a tenancy agreement. (5) Put landlords and prospective tenants in contact with each other.", "WHAT REQUIRES A LICENCE (DO NOT DO WITHOUT ONE): Charging fees for finding housing, collecting rent on behalf of a landlord, managing a property on behalf of a landlord, or advertising properties for rent without being a regulated letting agent. Doing these things without a licence is illegal under the Estate Agents Act 1979 and the Letting Agents legislation. You can be fined and prosecuted.", "TENANT FEES ACT 2019: It is ILLEGAL to charge prospective tenants any fees to help them find a home. This applies whether you are registered or not. You cannot charge for viewings, introductions, or 'finding' a property. The only exception is for Assured Shorthold Tenancy holding deposits (capped at 1 week's rent), which can only be taken directly by landlords or licensed agents.", "RIGHT TO RENT CHECKS: Any landlord renting to someone in the UK is legally required to check that tenant's right to rent. As a community housing helper, you should understand this and help community members prepare their Right to Rent share code in advance. Remind landlords they cannot discriminate by nationality — it is unlawful under the Equality Act 2010.", "ETHICAL CONSIDERATIONS: Never take money from either side. Never pressure a community member to take unsuitable accommodation. Never use your community trust to benefit yourself financially. Avoid informal arrangements where rent is paid in cash through you to the landlord — this creates legal risk for you and the tenant.", "BECOMING A REGISTERED LETTING AGENT (the legal route to earn from this work): To legally manage property or charge fees, you must join a government-approved redress scheme: Property Ombudsman (TPO) or Property Redress Scheme (PRS). Letting agents must also be members of a client money protection scheme. Start-up costs are approximately £500–£2,000/year. Consider this route once you have UK work rights and experience.", "HOUSING CHARITIES THAT NEED BILINGUAL HELPERS: Refugees at Home (refugeesathome.org), NACCOM (naccom.org.uk), local refugee housing charities, and housing advice centres. Volunteering with these organisations as a bilingual community liaison is valuable experience and entirely legal.", "IF A LANDLORD ASKS YOU TO FIND TENANTS REGULARLY: They may offer you an informal introduction fee. This is a legal grey area — a single informal finder's fee from a landlord (not a tenant) is not clearly prohibited, but it can create tax obligations (declare it as self-employment income) and could imply you are acting as an unlicensed agent if done regularly. Seek advice from a solicitor or Citizens Advice before accepting payment.", "⭐ SUMMARY OF SAFE HELP: Share information freely, translate, accompany, connect — but never charge tenants, never collect rent, and never manage property without being licensed. Your community role has genuine value — protect yourself by staying within these boundaries."] } }, cost: "Free (as community helper) | £500–£2,000/year (as licensed agent)", time: "Can help immediately (as community helper)", bring: [], links: [{ name: "Property Ombudsman (redress scheme)", url: "https://www.tpos.co.uk" }, { name: "Property Redress Scheme", url: "https://www.theprs.co.uk" }, { name: "Letting agent rules (GOV.UK)", url: "https://www.gov.uk/lettings-agency-work-uk" }, { name: "Tenant Fees Act guidance (GOV.UK)", url: "https://www.gov.uk/government/publications/tenant-fees-act-2019-guidance" }, { name: "Refugees at Home (connect refugees with hosts)", url: "https://www.refugeesathome.org" }, { name: "NACCOM (refugee housing network)", url: "https://naccom.org.uk" }] },
];

